export const MARK: Record<number, { verse: number; text: string }[]> = {
  1: [
  { verse: 1, text: "დასაწყისი იესო ქრისტეს, ღმერთის ძის, სახარებისა." },
  { verse: 2, text: "როგორც დაიწერა ესაია წინასწარმეტყველის მიერ: აჰა, მე ვგზავნი ჩემს ანგელოზს შენს წინაშე, რომელიც განამზადებს შენს გზას." },
  { verse: 3, text: "ხმა უდაბნოში მღაღადებლისა: გაამზადეთ გზა უფლისა, გაასწორეთ მისი ბილიკნი." },
  { verse: 4, text: "იყო იოანე უდაბნოში, ნათელს სცემდა და ქადაგებდა ნათლის ცემას სინანულისას ცოდვათა მისატევებლად." },
  { verse: 5, text: "გამოდიოდა მის მიმართ მთელი იუდეის ქვეყანა და ყველა იერუსალიმელი, ნათელს იღებდნენ მისგან მდინარე იორდანეში და აღიარებდნენ თავიანთ ცოდვებს." },
  { verse: 6, text: "ხოლო იოანეს ემოსა აქლემის ბეწვი და წელს ერტყა ტყავის სარტყელი და ჭამდა კალიებს და ველურ თაფლს." },
  { verse: 7, text: "ქადაგებდა და ამბობდა: მოდის ჩემს შემდგომ ჩემზე უძლიერესი, ვის წინაშე იმის ღირსიც არა ვარ, რომ დავიხარო და გავხსნა მისი ხამლის საკვრელი." },
  { verse: 8, text: "მე თქვენ მოგნათლეთ წყლით, ხოლო ის მოგნათლავთ სული წმიდით." },
  { verse: 9, text: "და იყო იმ დღეებში, მოვიდა იესო გალილეის ნაზარეთით და ნათელ იღო იორდანეში იოანესგან." },
  { verse: 10, text: "წყლიდან ამოსვლისთანავე იხილა ცანი გახსნილნი და სული ღმრთისა მტრედივით გადმომავალი მასზე." },
  { verse: 11, text: "და გაისმა ხმა ზეცით: შენა ხარ ძე ჩემი საყვარელი, რომელიც შევიტკბე მე." },
  { verse: 12, text: "და სულმა მაშინვე გაიყვანა ის უდაბნოში." },
  { verse: 13, text: "ორმოცი დღე დაჰყო უდაბნოში და გამოიცდებოდა სატანისაგან: მხეცებს შორის ცხოვრობდა და ანგელოზები ემსახურებოდნენ მას." },
  { verse: 14, text: "ხოლო იოანეს შეპყრობის შემდეგ მოვიდა იესო გალილეაში, და ქადაგებდა სახარებას ღმრთისას." },
  { verse: 15, text: "და ამბობდა: გასრულდა ჟამი და მოახლოვდა ღმრთის სასუფეველი: მოინანიეთ და იწამეთ სახარება." },
  { verse: 16, text: "ხოლო როდესაც მიდიოდა გალილეის ზღვის პირას, დაინახა სიმონი და მისი ძმა ანდრია, რომლებიც ბადეს ისროდნენ ზღვაში, ვინაიდან მებადურები იყვნენ." },
  { verse: 17, text: "და უთხრა მათ იესომ: მოდით, უკან გამომყევით და კაცთა მებადურებად გაქცევთ." },
  { verse: 18, text: "მათაც მყისვე მიატოვეს თავიანთი ბადე და გაჰყვნენ მას." },
  { verse: 19, text: "იქიდან ცოტა რომ გამოვლო, დაინახა იაკობი ზებედესი და მისი ძმა იოანე, რომლებიც ბადეს კემსავდნენ ნავში." },
  { verse: 20, text: "და მაშინვე მოუხმო. მათაც მიატოვეს თავიანთი მამა ზებედე, ნავში მყოფ მუშებთან ერთად, და გაჰყვნენ მას." },
  { verse: 21, text: "მივიდნენ კაპერნაუმს და მაშინვე, შაბათ დღეს, შევიდა სინაგოგაში და ასწავლიდა მათ." },
  { verse: 22, text: "უკვირდათ მისი მოძღვრება, ვინაიდან ის ასწავლიდა მათ, როგორც ძალმოსილი, და არა როგორც მწიგნობარნი." },
  { verse: 23, text: "იყო მათ სინაგოგაში უწმინდური სულით შეპყრობილი კაცი, რომელმაც შეჰყვირა და თქვა:" },
  { verse: 24, text: "რა ხელი გაქვს ჩვენთან, იესო ნაზარეველო? ჩვენს დასაღუპად მოსულხარ! გიცნობ, ვინცა ხარ, ღმერთის წმიდანო." },
  { verse: 25, text: "მაგრამ შერისხა იგი იესომ და თქვა: ხმა გაკმინდე და გამოდი მაგისგან." },
  { verse: 26, text: "შეარყია იგი უწმინდურმა სულმა და ხმამაღალი ყვირილით გამოვიდა მისგან." },
  { verse: 27, text: "განცვიფრდა ყველა, ისე რომ, ერთმანეთს ეკითხებოდნენ და ამბობდნენ: რა არის ეს? რა არის ეს ახალი მოძღვრება, რომ ძალმოსილებით უწმინდურ სულებსაც უბრძანებს, და ისინიც ემორჩილებიან მას?" },
  { verse: 28, text: "და მალე მისი ამბავი კიდით-კიდემდე მოედო მთელი გალილეის მხარეს." },
  { verse: 29, text: "სინაგოგიდან გამოსვლისთანავე სიმონისა და ანდრიას სახლში მივიდა, იაკობსა და იოანესთან ერთად." },
  { verse: 30, text: "ხოლო სიმონის სიდედრი ცხელებით შეპყრობილი იწვა. და მაშინვე უთხრეს მისი ამბავი." },
  { verse: 31, text: "მივიდა, ხელი მოჰკიდა და წამოაყენა; მყისვე გაუარა ცხელებამ და ემსახურებოდა მათ." },
  { verse: 32, text: "ხოლო საღამოს, მზის ჩასვლისას, მიჰგვარეს მას ყველა სნეული და ეშმაკეული." },
  { verse: 33, text: "და მთელმა ქალაქმა კარწინ მოიყარა თავი." },
  { verse: 34, text: "მრავალი სნეული განკურნა სხვადასხვა სენისაგან, მრავალი ეშმაკი განდევნა და არა რთავდა ეშმაკებს იმის თქმის ნებას, რომ ისინი იცნობდნენ მას." },
  { verse: 35, text: "ხოლო ცისკრისას, დილაუთენია ადგა და გამოვიდა; უდაბურ ადგილას მივიდა და იქ ლოცულობდა." },
  { verse: 36, text: "თან გაჰყვნენ სიმონი და მასთან მყოფნი." },
  { verse: 37, text: "იპოვეს იგი და უთხრეს, ყველა შენ გეძებსო." },
  { verse: 38, text: "და უთხრა მათ: წავიდეთ მახლობელ სოფლებსა და ქალაქებში, რათა იქაც ვიქადაგო, ვინაიდან ამისათვის მოვსულვარ." },
  { verse: 39, text: "დადიოდა მთელს გალილეაში, ქადაგებდა მათ სინაგოგებში და აძევებდა ეშმაკთ." },
  { verse: 40, text: "მაშინ მიადგა ერთი კეთროვანი, ევედრებოდა და მუხლმოყრით ეუბნებოდა: თუ გნებავს, შეგიძლია ჩემი განწმენდა." },
  { verse: 41, text: "შეებრალა იგი იესოს, ხელი გაიწოდა, შეეხო და უთხრა: მნებავს, განიწმინდე;" },
  { verse: 42, text: "ამის თქმაც იყო და მყისვე გაეყარა მას კეთრი და განიწმინდა." },
  { verse: 43, text: "მკაცრად გააფრთხილა და მაშინვე გაისტუმრა იგი." },
  { verse: 44, text: "უთხრა: იცოდე ნურავის ნურაფერს ეტყვი, არამედ წადი, ეჩვენე მღვდელს და შესწირე შენი განწმენდისათვის, რაც ბრძანა მოსემ მათდა სამოწმებლად." },
  { verse: 45, text: "მაგრამ ის გამოვიდა, დაიწყო ქადაგება და მთელ ქვეყანას მოსდო მისი ამბავი; ასე რომ, იესოს აღარ შეეძლო ქალაქში აშკარად შესვლა, არამედ გარეთ, უდაბურ ადგილებში იყო, და მოდიოდნენ მასთან ყოველი მხრიდან." }
],
2: [
  { verse: 1, text: "რამდენიმე დღის შემდეგ კვლავ შევიდა კაპერნაუმში; და გავარდა ხმა: შინ არისო." },
  { verse: 2, text: "და მაშინვე იმდენმა ხალხმა მოიყარა თავი, რომ კართანაც აღარ დარჩა ადგილი; და ეუბნებოდა მათ სიტყვას." },
  { verse: 3, text: "მოვიდნენ და მოჰგვარეს დავრდომილი, რომელიც ოთხ კაცს მოჰყავდა." },
  { verse: 4, text: "და რაკი ხალხის სიმრავლის გამო ვერ შესძლეს მასთან მისვლა, სახურავი ახადეს სახლს, სადაც ის იმყოფებოდა, და ჭერიდან ჩაუშვეს სარეცელი, რომელზედაც დავრდომილი იწვა." },
  { verse: 5, text: "მათი რწმენა რომ იხილა, იესომ უთხრა დავრდომილს: შვილო, მოგეტევა შენი ცოდვები." },
  { verse: 6, text: "იჯდა იქ ზოგიერთი მწიგნობარი და გულში ამბობდა:" },
  { verse: 7, text: "ამას რას ამბობს? ღმერთსა ჰგმობს: ვის შეუძლია ცოდვათა მიტევება, გარდა ერთისა - ღმერთისა?" },
  { verse: 8, text: "ხოლო იესომ მყისვე შეიცნო სულით, რასაც ფიქრობდნენ, და უთხრა მათ: რად ფიქრობთ მაგას თქვენს გულში?" },
  { verse: 9, text: "რა უფრო ადვილია: ამისი თქმა დამბლადაცემულის მიმართ: მოგეტევოს შენი ცოდვები; თუ ამისა: აღდეგ, აიღე შენი სარეცელი და წადი?" },
  { verse: 10, text: "მაგრამ რათა იცოდეთ, რომ ძეს კაცისას ძალი შესწევს ამ ქვეყნად ცოდვათა მიტევებისა, - უთხრა დავრდომილს:" },
  { verse: 11, text: "შენ გეუბნები: აღდეგ, აიღე შენი სარეცელი და წადი შენს სახლში." },
  { verse: 12, text: "ისიც მაშინვე აღდგა, აიღო თავისი სარეცელი და გამოვიდა ყველას წინაშე, ისე რომ, უკვირდა ყველას, ადიდებდნენ ღმერთს და ამბობდნენ: არასოდეს ამგვარი რამ არ გვინახავსო." },
  { verse: 13, text: "და კვლავ გამოვიდა იესო ზღვის პირას: მთელი ხალხი დაიძრა მისკენ, და ასწავლიდა მათ." },
  { verse: 14, text: "გზად მიმავალმა დაინახა ლევი ალფესი, რომელიც საბაჟოში იჯდა, და უთხრა მას, გამომყევიო: ისიც ადგა და გაჰყვა." },
  { verse: 15, text: "ხოლო როცა ინახად იჯდა მის სახლში, ბევრი მებაჟე და ცოდვილი იჯდა იესოსა და მის მოწაფეებთან ერთად, ვინაიდან მრავალნი იყვნენ და მისდევდნენ მას." },
  { verse: 16, text: "როცა მწიგნობრებმა და ფარისევლებმა დაინახეს, რომ მებაჟეებსა და ცოდვილებთან ერთად ჭამდა, მის მოწაფეებს უთხრეს: რატომ ჭამს მებაჟეებსა და ცოდვილებთან ერთად?" },
  { verse: 17, text: "ეს რომ გაიგონა, იესომ უთხრა მათ: კარგად მყოფთ კი არ სჭირდებათ მკურნალი, არამედ ავადმყოფთ: მართალთა სახმობლად კი არ მოვედი, არამედ ცოდვილთა სინანულად." },
  { verse: 18, text: "იოანეს მოწაფეები და ფარისევლები მარხულობდნენ. მივიდნენ და უთხრეს მას: რატომ მარხულობენ იოანეს მოწაფეები და ფარისევლები, შენი მოწაფეები კი არა?" },
  { verse: 19, text: "ხოლო იესომ მიუგო მათ: განა შეიძლება მარხულობდნენ მექორწილენი, ვიდრე მათთანაა სიძე? სანამდის სიძე გვერდითა ჰყავთ, ვერ იმარხულებენ." },
  { verse: 20, text: "დადგება დღე, როცა სიძე აღარ ეყოლებათ, და მაშინ იმარხულებენ." },
  { verse: 21, text: "არავინ ადებს ახალ საკერებელს დახეულ სამოსს, ვინაიდან ახალს ვერ დაიჭერს ძველი და უფრო დაიხევა." },
  { verse: 22, text: "არც ახალ ღვინოს ასხამს ვინმე ძველ ტიკებში; თორემ დახეთქს ახალი ღვინო ძველ ტიკებს, ღვინოც დაიქცევა და ტიკებიც უვარგისი გახდება. არამედ ახალ ღვინოს ახალ ტიკებში ასხამენ." },
  { verse: 23, text: "მოხდა ისე, რომ შაბათ დღეს ყანაში მიდიოდა, და მისმა მოწაფეებმა გზადაგზა თავთავებს დაუწყეს კრეფა." },
  { verse: 24, text: "ფარისევლებმა უთხრეს: შეხედე, რატომ აკეთებენ იმას, რაც ნებადართული არ არის შაბათს?" },
  { verse: 25, text: "ხოლო იესომ მიუგო მათ: ნუთუ არასოდეს წაგიკითხავთ, როგორ მოიქცა დავითი, როცა გაუჭირდა და მოშივდა მასაც და მასთან მყოფთაც?" },
  { verse: 26, text: "როგორ შევიდა ღმერთის სახლში, აბიათარის მღვდელმთავრობისას, და შეჭამა შესაწირავი პური, რისი ჭამის ნებაც არავის ჰქონდა, გარდა მღვდლებისა, და მისცა მასთან მყოფთაც?" },
  { verse: 27, text: "და უთხრა მათ: შაბათი კაცისათვის შეიქმნა, და არა კაცი შაბათისათვის." },
  { verse: 28, text: "ასე რომ, ძე კაცისა შაბათის უფალიც არის." }
],

3: [
  { verse: 1, text: "კვლავ შევიდა სინაგოგაში, და იყო იქ ხელგამხმარი კაცი." },
  { verse: 2, text: "და უთვალთვალებდნენ მას, ვნახოთ, შაბათს თუ განკურნავსო, რათა ბრალი დაედოთ მისთვის." },
  { verse: 3, text: "ხოლო მან უთხრა ხელგამხმარ კაცს: შუაში დადექ." },
  { verse: 4, text: "მათ კი უთხრა: რისი ქმნა შეიძლება შაბათს: კეთილისა თუ ბოროტისა? სულის ცხონება თუ წარწყმედა? ხოლო ისინი დუმდნენ." },
  { verse: 5, text: "რისხვით მოავლო თვალი შეკრებილთ, მათი გულქვაობით დამწუხრებულმა, და უთხრა ხელგამხმარ კაცს: გაიწოდე შენი ხელი! მანაც გაიწოდა და კვლავ გაუმრთელდა, როგორც მეორე." },
  { verse: 6, text: "გამოვიდნენ თუ არა ფარისევლები, სასწრაფოდ მოითათბირეს ჰეროდელებთან ერთად, როგორ დაეღუპათ იგი." },
  { verse: 7, text: "მაგრამ იესო მოწაფეებითურთ ზღვის პირას გავიდა; და მიჰყვა მას დიდძალი ხალხი გალილეიდან და იუდეიდან," },
  { verse: 8, text: "იერუსალიმიდან, იდუმეიდან და იორდანეს გაღმიდან. ტიროსისა და სიდონის მხარის მცხოვრებთაც შეიტყეს მისი საქმენი, და მრავალი მივიდა მასთან." },
  { verse: 9, text: "და, ხალხმრავლობის გამო, თავის მოწაფეებს უთხრა, ნავი გამიმზადეთო, რათა არ შეევიწროებინათ იგი." },
  { verse: 10, text: "ვინაიდან მრავალი განეკურნა: ასე რომ, ყველა სნეული აწყდებოდა, რათა შეხებოდა მას." },
  { verse: 11, text: "მისი შემყურე უწმინდური სულები მის წინაშე ემხობოდნენ და ყვიროდნენ: შენა ხარ ძე ღმრთისა." },
  { verse: 12, text: "ხოლო იესომ მკაცრად უბრძანა მათ, არ გამთქვათო." },
  { verse: 13, text: "მერე ავიდა მთაზე და მოუხმო მათ, ვინც თვითონ სურდა; და მივიდნენ მასთან." },
  { verse: 14, text: "აირჩია თორმეტი, რათა ყოფილიყვნენ მასთან და საქადაგებლად წარეგზავნა ისინი," },
  { verse: 15, text: "და რათა ჰქონოდათ სნეულთა განკურნებისა და ეშმაკთა განდევნის ძალა." },
  { verse: 16, text: "აირჩია თორმეტი, და სიმონს სახელად უწოდა პეტრე." },
  { verse: 17, text: "ხოლო იაკობს ზებედესას და იაკობის ძმას იოანეს უწოდა ბოანერგეს, რაც ნიშნავს: ქუხილის ძენი;" },
  { verse: 18, text: "ანდრია და ფილიპე, ბართლომე და მათე, თომა და იაკობ ალფესი, თადეოსი და სიმონ კანანელი." },
  { verse: 19, text: "და იუდა ისკარიოტელი, რომელმაც გასცა იგი." },
  { verse: 20, text: "მივიდა სახლში, და კვლავ შეგროვდა იმდენი ხალხი, რომ პურის ჭამა ვეღარ შეიძლეს." },
  { verse: 21, text: "გაიგეს მისმა ახლობლებმა და მოვიდნენ, რათა შეეპყროთ იგი, ვინაიდან ამბობდნენ, შეიშალაო." },
  { verse: 22, text: "ხოლო იერუსალიმიდან ჩამოსული მწიგნობრები ამბობდნენ: ბელზებული ჰყავს და ეშმაკთა მთავრის შეწევნით აძევებსო ეშმაკთ." },
  { verse: 23, text: "მაშინ მოუხმო და იგავით უთხრა მათ: როგორ შეუძლია სატანას სატანის გაძევება?" },
  { verse: 24, text: "თუ სამეფო თავის თავს განეყოფა, ვერ გაძლებს ის სამეფო." },
  { verse: 25, text: "და თუ სახლი თავის თავს განეყოფა, ვერ გაძლებს ის სახლი." },
  { verse: 26, text: "ხოლო თუ სატანა წინ აღუდგება და განეყოფა თავის თავს, ვერ გაძლებს, არამედ ახლოა მისი აღსასრული." },
  { verse: 27, text: "ვერც ვერავინ შევა ძლიერის სახლში და გაძარცვავს მას, თუკი თავდაპირველად არ შებოჭავს ძლიერს. მხოლოდ ამის შემდეგ თუ შესძლებს გაძარცვოს მისი სახლი." },
  { verse: 28, text: "ჭეშმარიტად გეუბნებით თქვენ: ყოველი ცოდვა და გმობა მიეტევება კაცთ, რამდენსაც უნდა ჰგმობდნენ." },
  { verse: 29, text: "მაგრამ ვინც იტყვის სულის წმიდის გმობას, არა აქვს მიტევება უკუნისამდე, არამედ ღირსია საუკუნო სასჯელისა." },
  { verse: 30, text: "ასე თქვა, იმიტომ რომ ამბობდნენ: უწმინდური სული ჰყავსო." },
  { verse: 31, text: "მოვიდნენ მისი დედა და ძმები, გარეთ გაჩერდნენ და კაცი შეუგზავნეს დასაძახებლად." },
  { verse: 32, text: "დიდძალი ხალხი ეხვია გარს, როდესაც უთხრეს: აჰა, დედაშენი და შენი და-ძმანი გარეთ დგანან და გკითხულობენო." },
  { verse: 33, text: "ხოლო იესომ მიუგო მათ: ვინ არის დედაჩემი, ან ჩემი ძმები?" },
  { verse: 34, text: "თვალი მოავლო ირგვლივ მსხდომთ და თქვა: აი, დედაჩემი და ჩემი ძმები." },
  { verse: 35, text: "რადგან ვინც აღასრულებს ღმერთის ნებას, იგია ჩემი ძმაც, ჩემი დაცა და დედაც." }
],

4: [
  { verse: 1, text: "კვლავ დაიწყო სწავლება ზღვის პირას და შეგროვდა მის ირგვლივ იმდენი ხალხი, რომ ნავში ჩაჯდა და ზღვაში შევიდა, ხოლო მთელი ხალხი ზღვის პირას, ხმელეთზე იყო." },
  { verse: 2, text: "ბევრ რასმე ასწავლიდა იგავებით და თავისი სწავლით ამბობდა:" },
  { verse: 3, text: "ისმინეთ: აჰა, გამოვიდა მთესავი თესვად." },
  { verse: 4, text: "ხოლო თესვისას ზოგი მარცვალი გზის პირას დავარდა; მოფრინდნენ ცის ფრინველები და აკენკეს ისინი." },
  { verse: 5, text: "ზოგიც ქვიან ადგილას დავარდა, სადაც ბლომად არ იყო მიწა და მალე აღმოცენდა, ვინაიდან ნიადაგი არ იყო ღრმა." },
  { verse: 6, text: "მაგრამ ამოვიდა თუ არა მზე, დაჭკნა, და რადგან ფესვი არ ჰქონდა, გახმა." },
  { verse: 7, text: "ზოგი კი ეკალ-ბარდებში ჩაცვივდა; წამოიზარდა ეკალი და ერთიანად მოაშთო ყველა; და ვეღარ გამოიღეს ნაყოფი." },
  { verse: 8, text: "ხოლო ზოგი პოხიერ ნიადაგზე დაეცა, იზარდა, ნაყოფი გამოიღო და იმატა: ერთი ოცდაათად, ერთი სამოცად თუ ერთი ასად." },
  { verse: 9, text: "და უთხრა მათ: ვისაც ყური აქვს სმენად, ისმინოს!" },
  { verse: 10, text: "როდესაც ხალხი დაიშალა, მასთან დარჩენილებმა თორმეტ მოწაფესთან ერთად ჰკითხეს იგავის აზრი." },
  { verse: 11, text: "და უთხრა მათ: თქვენ მოგეცათ ღმრთის სასუფევლის საიდუმლოთა ცოდნა, ხოლო გარეშეთათვის ყველაფერი იგავში ხდება." },
  { verse: 12, text: "რადგან თვალით მხედველნი ვერას ხედავენ, და ყურით მსმენელნი ვერას ისმენენ, რათა არ მოიქცნენ და არ მიეტევოთ ცოდვები." },
  { verse: 13, text: "და უთხრა მათ: ეს იგავი არ გესმით და როგორღა გაიგებთ დანარჩენთ?" },
  { verse: 14, text: "მთესავი სიტყვას თესავს." },
  { verse: 15, text: "გზის პირას დაცვენილი თესლი ისინი არიან, რომლებშიაც ითესება სიტყვა, მაგრამ სიტყვის მოსმენისთანავე მიადგებათ სატანა და მოსტაცებთ სიტყვას, რომელიც მათ გულში ჩაითესა." },
  { verse: 16, text: "ასევე, ქვიან ადგილას დაცვენილი თესლი ისინი არიან, რომელნიც სიტყვის მოსმენისთანავე სიხარულით იღებენ მას;" },
  { verse: 17, text: "მაგრამ ფესვი არა აქვს მათში, და როდესაც მოაწევს ჭირის დღე ან დევნა სიტყვის გამო, მყისვე ცდებიან." },
  { verse: 18, text: "ეკალ-ბარდებში ჩაცვენილი თესლი სიტყვის მსმენელნი არიან," },
  { verse: 19, text: "რომლებშიაც სოფლის საზრუნავი, სიმდიდრის საცდური და სხვა გულისთქმანი, მათში შესვლისას, აშთობენ სიტყვას და უნაყოფოს ხდიან მას." },
  { verse: 20, text: "ხოლო პოხიერ ნიადაგზე დაცვენილი თესლი ისინი არიან, რომელნიც ისმენენ და კიდევაც იღებენ სიტყვას, და ნაყოფიც გამოაქვთ: ერთი ოცდაათად, ერთი სამოცად თუ ერთი ასად." },
  { verse: 21, text: "და უთხრა მათ: განა იმიტომ მოაქვთ სანთელი, რომ საწყაოსა თუ საწოლის ქვეშ დადგან? არამედ სასანთლეზე დგამენ მას." },
  { verse: 22, text: "არ არსებობს დაფარული, რომ არ გამოჩნდეს, და არც რამ საიდუმლო, რომ არ გამჟღავნდეს." },
  { verse: 23, text: "ვისაც ყური აქვს სმენად, ისმინოს!" },
  { verse: 24, text: "და უთხრა მათ: დაუკვირდით, რაც გესმით: რომელი საწყაულითაც მიუწყავთ, იმითვე მოგეწყვით და მოგემატებათ." },
  { verse: 25, text: "რადგან ვისაც აქვს, მას მიეცემა, ხოლო ვისაც არა აქვს, წაერთმევა ისიც, რაც აქვს." },
  { verse: 26, text: "და თქვა: ღმრთის სასუფეველი იმასა ჰგავს, კაცი რომ თესლს ჩათესავს მიწაში." },
  { verse: 27, text: "სძინავს თუ დგება, დღისით თუ ღამით, არც იცის, როგორ აღმოცენდება და იზრდება თესლი." },
  { verse: 28, text: "რადგანაც მიწას თავისთავად გამოაქვს ნაყოფი: ჯერ ღერო, შემდეგ თავთავი, ბოლოს, სავსე მარცვალი თავთავში." },
  { verse: 29, text: "და როცა დამწიფდება ნაყოფი, მაშინვე გაგზავნის ნამგალს, ვინაიდან დამდგარა მკის ჟამი." },
  { verse: 30, text: "და თქვა: რას ვამსგავსო ღმრთის სასუფეველი? ან რომელი იგავით წარმოგისახოთ იგი?" },
  { verse: 31, text: "ესაა მდოგვის მარცვალი, რომელიც მიწაში ჩათესვისას ყველა თესლზე უმცირესია ამ ქვეყნად." },
  { verse: 32, text: "მაგრამ დათესვის შემდეგ ამოდის, ყველა მწვანილზე დიდი იზრდება და ისე ფართოდ შლის ტოტებს, რომ ცის ფრინველებს შეუძლიათ მის ჩრდილში დაიბუდონ." },
  { verse: 33, text: "ბევრი ასეთი იგავით ეუბნებოდა მათ სიტყვას, რამდენის მოსმენაც შეეძლოთ." },
  { verse: 34, text: "ხოლო უიგავოდ არაფერს ეტყოდა მათ; თავის მოწაფეებს კი განმარტოებით უხსნიდა ყველაფერს." },
  { verse: 35, text: "იმ დღეს, მწუხრის ჟამს, უთხრა მათ: გაღმა გავიდეთო." },
  { verse: 36, text: "გაისტუმრეს ხალხი და წაიყვანეს იგი ნავით, რომელშიც იჯდა. და სხვა ნავებიც მისდევდნენ მას." },
  { verse: 37, text: "ამოვარდა საშინელი ქარიშხალი და ტალღები ეხეთქებოდნენ ნავს, ისე რომ, ლამის წყლით აივსო იგი." },
  { verse: 38, text: "ხოლო ის კიჩოზე იწვა და სასთუმალზე ეძინა. გააღვიძეს და უთხრეს: მოძღვარო, არ გენაღვლება, რომ ვიღუპებით?" },
  { verse: 39, text: "მაშინ წამოდგა, შერისხა ქარი და უბრძანა ზღვას: დაყუჩდი, დაცხრი! და ჩამოვარდა სიმყუდროვე დიდი." },
  { verse: 40, text: "და უთხრა მათ: რატომ ხართ ასე მოშიშარნი? რატომ არა გაქვთ რწმენა?" },
  { verse: 41, text: "ისინი საშინელი ძრწოლით შეძრწუნდნენ და ერთმანეთს ეუბნებოდნენ: ვინ არის იგი, ქარიც და ზღვაც რომ მორჩილებენ?" }
],
  5: [
  { verse: 1, text: "გავიდნენ ზღვის გაღმა და მიადგნენ გერასენელთა მხარეს." },
  { verse: 2, text: "ნავიდან გადმოსვლისთანავე სამარხებიდან შემოეგება უწმინდური სულით შეპყრობილი კაცი," },
  { verse: 3, text: "რომელსაც სამყოფლად სამარხები ჰქონდა და ჯაჭვითაც არავის შეეძლო მისი დაბმა," },
  { verse: 4, text: "ვინაიდან მრავალგზის შეეკრათ ჯაჭვით და ბორკილებიც დაედოთ, მაგრამ გლეჯდა ჯაჭვს, ამსხვრევდა ბორკილებს და ვერავის დაეოკებინა იგი." },
  { verse: 5, text: "დღე და ღამ მთებსა და სამარხებში დაძრწოდა, ღრიალებდა და ქვებს ახეთქებდა თავს." },
  { verse: 6, text: "შორიდან რომ მოჰკრა თვალი იესოს, გამოიქცა და თაყვანი სცა მას." },
  { verse: 7, text: "შეღაღადა და შესძახა: რა ხელი გაქვს ჩემთან, იესო, ძეო მაღალი ღმრთისაო: გაფიცებ შენს ღმერთს, ნუ მტანჯავ მე!" },
  { verse: 8, text: "რადგანაც იესომ უთხრა: გამოდი, სულო უწმინდურო, მაგ კაცისაგან!" },
  { verse: 9, text: "და ჰკითხა მას: რა გქვია სახელად? ხოლო მან მიუგო: ლეგიონია ჩემი სახელი, ვინაიდან მრავალნი ვართ." },
  { verse: 10, text: "და ბევრი ევედრა, რათა იქიდან არ გაეძევებინა ისინი." },
  { verse: 11, text: "იქვე, მთის ფერდობზე, ბალახობდა ღორების დიდი კოლტი." },
  { verse: 12, text: "უწმინდურებმა მუდარით უთხრეს მას: გაგვგზავნე ღორებში, რომ მათში შევიდეთო." },
  { verse: 13, text: "მაშინ ნება დართო იესომ და გამოვიდნენ უწმინდური სულნი, ღორებში შევიდნენ, და მთელი კოლტი, ორი ათასამდე სული, ზღვის კბოდეს მიაწყდა და წყალში ჩაიხრჩო." },
  { verse: 14, text: "ხოლო მეღორეები გაიქცნენ და ქალაქსა და სოფლებს მოსდეს ეს ამბავი. და გამოვიდა მთელი ხალხი, რათა თავისი თვალით ეხილა, რაც მოხდა." },
  { verse: 15, text: "მივიდნენ იესოსთან და დაინახეს, რომ ეშმაკეული, რომელსაც ჰყავდა ლეგიონი, ზის ჩაცმულ-დახურული და გონს მოსული; და შეძრწუნდნენ." },
  { verse: 16, text: "ხოლო მხილველებმა უამბეს მათ, რაც დაემართა ეშმაკეულსა და ღორებს." },
  { verse: 17, text: "და დაუწყეს ვედრება, აქაურობას გაეცალეო." },
  { verse: 18, text: "ნავში რომ ჯდებოდა, ნაეშმაკეულევმა სთხოვა, თან წაეყვანა." },
  { verse: 19, text: "მაგრამ იესომ ნება არ დართო და უთხრა: შინ წადი, შენიანებთან, და უამბე მათ, რა გიყო უფალმა და როგორ შეგიწყალა." },
  { verse: 20, text: "ისიც წავიდა და დაიწყო ქადაგება ათქალაქში, რა უყო მას იესომ, და უკვირდა ყველას." },
  { verse: 21, text: "როცა იესო კვლავ გამოვიდა ნავით გამოღმა მხარეს, დიდძალი ხალხი შეგროვდა მასთან. და იყო იგი ზღვის პირას." },
  { verse: 22, text: "და, აჰა, მივიდა მასთან სინაგოგის ერთი წინამძღვარი, სახელად იაიროსი, და, დაინახა თუ არა იგი, ფეხებში ჩაუვარდა." },
  { verse: 23, text: "გულმხურვალედ შეევედრა და უთხრა: ჩემი ასული სიკვდილის პირასაა. მოდი და ხელი დაადე, რათა მორჩეს და იცოცხლოს." },
  { verse: 24, text: "ისიც წაჰყვა; თან მისდევდა დიდძალი ხალხი და ზედ აწყდებოდა." },
  { verse: 25, text: "ერთმა ქალმა, რომელიც თორმეტ წელიწადს სისხლის დენით იტანჯებოდა," },
  { verse: 26, text: "ბევრი რამ დაეთმინა მრავალი მკურნალის ხელში, და დაეხარჯა ყველაფერი, რაც ებადა, მაგრამ არაფერში წასდგომოდა და, პირიქით, უარესად შექმნილიყო, -" },
  { verse: 27, text: "იესოს ამბავი რომ გაიგო, უკნიდან მიუახლოვდა ბრბოში და მის სამოსს შეეხო." },
  { verse: 28, text: "ვინაიდან გულში ამბობდა: მის სამოსსაც რომ შევეხო, მეშველებაო." },
  { verse: 29, text: "და მართლაც, შეხებისთანავე შეუწყდა სისხლის დენა, და ტანმა უგრძნო, რთმ განიკურნა სნეულებისგან." },
  { verse: 30, text: "მაგრამ მაშინვე იესომ თავადაც იგრძნო, რომ ძალა გავიდა მისგან, მიუბრუნდა ხალხს და იკითხა: ვინ შეეხო ჩემს სამოსს?" },
  { verse: 31, text: "ხოლო მოწაფეებმა უთხრეს: ხომ ხედავ, ხალხი ზედ გაწყდება და შენ კი კითხულობ, ვინ შემეხოო?" },
  { verse: 32, text: "იესომ მიმოიხედა, რათა დაენახა ამის ჩამდენი." },
  { verse: 33, text: "მაშინ ქალი, რომელიც მიხვდა, რაც დაემართა, შიშის კანკალით მიუახლოვდა, მის წინაშე დაემხო და მთელი სიმართლე მოახსენა." },
  { verse: 34, text: "ხოლო იესომ უთხრა: ასულო, შენმა რწმენამ გადაგარჩინა; წადი მშვიდობით, დახსნილი ხარ შენი სატანჯველისგან." },
  { verse: 35, text: "ამას რომ ამბობდა, სინაგოგის წინამძღვართან მივიდნენ და უთხრეს: შენი ასული აღესრულა; რატომღა აწუხებ მოძღვარს?" },
  { verse: 36, text: "ხოლო იესომ ამ სიტყვების გაგონებისთანავე უთხრა სინაგოგის წინამძღვარს: ნუ გეშინია, შენ მხოლოდ გწამდეს." },
  { verse: 37, text: "და არავის მისცა გაყოლის ნება, პეტრეს, იაკობისა და იოანეს, იაკობის ძმის, გარდა." },
  { verse: 38, text: "მივიდა სინაგოგის წინამძღვრის სახლში, და იხილა შფოთი, მოტირალნი და მოზარენი." },
  { verse: 39, text: "შევიდა და უთხრა მათ: რატომ შფოთავთ და მოსთქვამთ? გოგონა კი არ მომკვდარა, არამედ სძინავს." },
  { verse: 40, text: "ხოლო ისინი დასცინოდნენ მას. მან კი გარეთ გამოასხა ყველანი, შეიყოლა მხოლოდ ბავშვის დედ-მამა და შევიდა, სადაც გოგონა იწვა." },
  { verse: 41, text: "ხელი მოჰკიდა და უთხრა მას: ტალითა, კუმი! რაც თარგმანით ნიშნავს: შენ გეუბნები, პატარავ, აღდეგ!" },
  { verse: 42, text: "გოგონაც მაშინვე აღდგა და გაიარა; ხოლო ის თორმეტი წლისა იყო. და განცვიფრდნენ დიდად." },
  { verse: 43, text: "იესომ მკაცრად გააფრთხილა ისინი, რომ არავის გაეგო ეს, და უთხრა, საჭმელი მიეცათ გოგონასათვის." },
],
6: [
  { verse: 1, text: "წამოვიდა იქიდან და მოწაფეების თანხლებით მივიდა თავის მამულში." },
  { verse: 2, text: "შაბათ დღეს დაიწყო სწავლება სინაგოგაში და მრავალი მსმენელი გაოცებული ამბობდა: ვინ მისცა ყოველივე ეს, ან რა სიბრძნე აქვს ბოძებული, რომ ამნაირი სასწაულები ხდება მისი ხელით?" },
  { verse: 3, text: "განა ხურო არ არის, მარიამის ძე და იაკობის, იოსეს, იუდასა და სიმონის ძმა? მისი დებიც ხომ აქვე არიან, ჩვენს შორის? და ცდებოდნენ მასში." },
  { verse: 4, text: "ხოლო იესომ უთხრა მათ: არ არსებობს წინასწარმეტყველი პატივის გარეშე, თუ არა თავის მამულში, თავისიანებს შორის და თავის სახლში." },
  { verse: 5, text: "და არ მოუხდენია იქ არავითარი სასწაული. მხოლოდ რამდენიმე სნეულს დაადო ხელი და განკურნა." },
  { verse: 6, text: "უკვირდა მათი ურწმუნოება, ახლომახლო სოფლებში დადიოდა და ასწავლიდა მათ." },
  { verse: 7, text: "მოუხმო თორმეტს, წყვილ-წყვილად დაუწყო წარგზავნა, და მისცა მათ უწმინდურ სულთა დათრგუნვის ძალა." },
  { verse: 8, text: "და ამცნო მათ, არაფერი წაეღოთ გზაში, გარდა არგნისა; არცა აბგა, არც პური, არც რვალი სარტყლით:" },
  { verse: 9, text: "არამედ სცმოდათ მხოლოდ ხამლები, და ნუ იგულებდნენ ორ ხელ სამოსს." },
  { verse: 10, text: "და უთხრა მათ: თუ სადმე შეხვალთ სახლში, იქვე დარჩით, სანამ არ გამოხვალთ იქიდან." },
  { verse: 11, text: "ხოლო თუ არავინ მიგიღოთ და არც ისმინოს თქვენი, იქიდან გამოსვლისას, მათ სამოწმებლად ჩამოიბერტყეთ თქვენი ფეხიდან მტვერი. ჭეშმარიტად გეუბნებით თქვენ: განკითხვის დღე სოდომისა და გომორისთვის უფრო ასატანი იქნება, ვიდრე იმ ქალაქისათვის." },
  { verse: 12, text: "და წავიდნენ ისინი სინანულის საქადაგებლად." },
  { verse: 13, text: "აძევებდნენ მრავალ ეშმაკს, ზეთს სცხებდნენ და ჰკურნავდნენ უამრავ სნეულს." },
  { verse: 14, text: "ჰეროდე მეფემ გაიგო ეს (ვინაიდან გაცხადდა მისი სახელი) და თქვა: იოანე ნათლისმცემელი აღმდგარა მკვდრეთით და ამიტომ ძალნი მძლავრობენ მასში." },
  { verse: 15, text: "სხვები ამბობდნენ: ეს ელიაა; ზოგი კი ამბობდა: წინასწარმეტყველია, ანდა როგორც ერთი წინასწარმეტყველთაგანი." },
  { verse: 16, text: "ხოლო ჰეროდემ რომ გაიგო, თქვა: ეს იოანეა, რომელსაც მე მოვკვეთე თავი; მკვდრეთით აღმდგარა." },
  { verse: 17, text: "ვინაიდან ჰეროდემ თვითონ წარგზავნა ხალხი, შეაპყრობინა იოანე, შეკრა და საპყრობილეში ჩააგდო ჰეროდიადას, თავისი ძმის, ფილიპეს ცოლის გამო, ცოლად რომ შეერთო მას." },
  { verse: 18, text: "რადგან იოანე ეუბნებოდა ჰეროდეს: არ უნდა გყავდესო შენი ძმის ცოლი." },
  { verse: 19, text: "ამიტომ ჰეროდიადა სდევნიდა მას და ცდილობდა მოეკლა იგი, მაგრამ არ შეეძლო." },
  { verse: 20, text: "რადგანაც ჰეროდეს ეშინოდა იოანესი, ვინაიდან იცოდა, რომ მართალი და წმიდა კაცი იყო და უფრთხილდებოდა; ბევრ რამეს აკეთებდა მისი რჩევით და სიამოვნებით უსმენდა მას." },
  { verse: 21, text: "მაგრამ ქალმა დრო იხელთა, როცა ჰეროდემ თავისი დაბადების დღეს წვეულება გაუმართა თავის დიდებულებს, ათასისთავებსა და გალილეველ წარჩინებულებს;" },
  { verse: 22, text: "გამოვიდა ჰეროდიადას ასული, იცეკვა და მოხიბლა ჰეროდეც და მისი თანამეინახენიც. და უთხრა მეფემ ქალწულს: მითხარი, რაც გსურს, და მოგცემო." },
  { verse: 23, text: "და შეჰფიცა: რაც უნდა მთხოვო, მოგცემ, თუნდაც ჩემს ნახევარ სამეფოსო." },
  { verse: 24, text: "ხოლო ის გავიდა და დედამისს ჰკითხა: რა ვთხოვოო? და მან მიუგო: იოანე ნათლისმცემლის თავი." },
  { verse: 25, text: "მსწრაფლ შემობრუნდა მეფესთან და უთხრა: მინდა ახლავე მომართვა ლანგრით იოანე ნათლისმცემლის თავი." },
  { verse: 26, text: "შეწუხდა მეფე, მაგრამ ფიცისა და თანამეინახეთა რიდით ვერ იკადრა გაეწბილებინა იგი." },
  { verse: 27, text: "მაშინვე გაგზავნა თავისი მცველი და უბრძანა მოეტანა იოანეს თავი." },
  { verse: 28, text: "ისიც წავიდა, თავი მოჰკვეთა მას საპყრობილეში და ლანგრით მიართვა ქალწულს, ხოლო ქალწულმა მისცა დედამისს." },
  { verse: 29, text: "ეს რომ გაიგეს, იოანეს მოწაფეები წავიდნენ, გამოიტანეს მისი ნეშტი და ჩაასვენეს იგი სამარხში." },
  { verse: 30, text: "შეიკრიბნენ მოციქულები იესოსთან და უამბეს ყველაფერი, რაც ექმნათ და ესწავლებინათ." },
  { verse: 31, text: "ხოლო იესომ უთხრა მათ: წადით, განმარტოვდით უდაბურ ადგილას და ცოტა დაისვენეთ; - რადგან ბევრი იყო მომსვლელ-წამსვლელი და ჭამის დროც არ ჰქონდათ." },
  { verse: 32, text: "და მარტონი გაემგზავრნენ უდაბურ ადგილას ნავით." },
  { verse: 33, text: "მაგრამ ხალხმა დაინახა მიმავალნი, ბევრმა იცნო იგი და ქალაქებიდან ფეხდაფეხ მიჰყვნენ სირბილით, დაწინაურდნენ და მათზე ადრე მივიდნენ იქ." },
  { verse: 34, text: "გამოვიდა იესო, დაინახა დიდძალი ხალხი და შეებრალა ისინი, რადგანაც იყვნენ, როგორც უმწყემსო ცხვრები; და დაიწყო მათთვის მრავალი რამის სწავლება." },
  { verse: 35, text: "და რაკი დიდმა დრომ განვლო, მოწაფეები მივიდნენ და უთხრეს მას: უდაბურია ეს ადგილი და თანაც გვიანია უკვე;" },
  { verse: 36, text: "გაუშვი ისინი, რათა წავიდნენ ახლომახლო სოფლებსა თუ დაბებში პურის საყიდლად, ვინაიდან არაფერი აქვთ საჭმელი." },
  { verse: 37, text: "ხოლო მან პასუხად თქვა: თქვენ თვითონ მიეცით საჭმელი. მათ უთხრეს: რა ვქნათ, წავიდეთ, ვიყიდოთ ორასი დინარის პური და ამათ მივცეთ საჭმელად?" },
  { verse: 38, text: "მან კი იკითხა: რამდენი პური გაქვთ? წადით და ნახეთ. მათაც ნახეს და მოახსენეს: „ხუთი პური და ორი თევზი“." },
  { verse: 39, text: "მაშინ უბრძანა მათ, მწვანე მდელოზე ჯგუფ-ჯგუფად დაესხათ ხალხი." },
  { verse: 40, text: "და დასხდნენ რიგ-რიგად. ას-ასი და ორმოცდაათ-ორმოცდაათი." },
  { verse: 41, text: "აიღო ხუთი პური და ორი თევზი, ზეცად აღაპყრო თვალნი, აკურთხა, დატეხა პურები და მისცა თავის მოწაფეებს, რათა ჩამოერიგებინათ მათთვის; და ორი თევზიც უწილადა ყველას." },
  { verse: 42, text: "ყველამ ჭამა და გაძღა." },
  { verse: 43, text: "და გაავსეს პურისა და თევზის ნარჩენებით თორმეტი კალათი." },
  { verse: 44, text: "ხოლო იყო პურის მჭამელი ასე ხუთი ათასამდე კაცი." },
  { verse: 45, text: "მაშინვე აიძულა თავისი მოწაფეები, ნავში ჩამსხდარიყვნენ და მასზე ადრე გასულიყვნენ გაღმა, ბეთსაიდას, სანამდის თვითონ გაისტუმრებდა ხალხს." },
  { verse: 46, text: "ხოლო როდესაც გაისტუმრა ისინი, მთაზე ავიდა სალოცავად." },
  { verse: 47, text: "მწუხრის ჟამს ნავი შუაგულ ზღვაში იყო, თვითონ კი მარტო იდგა ხმელეთზე." },
  { verse: 48, text: "და დაინახა, რომ გაუჭირდათ ცურვა, ვინაიდან პირქარი ქროდა; ხოლო ღამის მეოთხე გუშაგობისას ზღვაზე სვლით მივიდა მათთან და დააპირა უკან მოეტოვებინა ისინი." },
  { verse: 49, text: "ხოლო მათ, ზღვაზე მომავალი რომ დაინახეს, მოჩვენება ეგონათ და ყვირილი მორთეს;" },
  { verse: 50, text: "რადგან მისმა ხილვამ თავზარი დასცა ყველას. და მაშინვე შეეხმიანათ იესო: მხნედ იყავით; მე ვარ, ნუ გეშინიათ." },
  { verse: 51, text: "ნავში ჩაუჯდა მათ და ქარიც ჩადგა, რამაც კიდევ უფრო განაცვიფრა ისინი." },
  { verse: 52, text: "რადგან ვერ მიმხვდარიყვნენ პურობის სასწაულს, ვინაიდან გამქისებულიყო მათი გული." },
  { verse: 53, text: "გავიდნენ გაღმა და მიადგნენ გენესარეთის მხარეს." },
  { verse: 54, text: "ნავიდან გადმოსვლისთანავე იცნეს იგი იქაურებმა." },
  { verse: 55, text: "შემოირბინეს მთელი ეს მხარე, და ყველგან, სადაც კი ესმოდათ, აქ არისო, სარეცლებით მიჰყავდათ მასთან სნეულნი." },
  { verse: 56, text: "სადაც უნდა შესულიყო - სოფლებში, დაბებსა თუ ქალაქებში, მოედნებზე აწვენდნენ თავიანთ სნეულთ და სთხოვდნენ, ნება მიეცი, შენი სამოსის კალთას შეეხონო; და ყველა, ვინც მას ეხებოდა, იკურნებოდა." },
],
7: [
  { verse: 1, text: "შეგროვდნენ მასთან ფარისევლები და იერუსალიმიდან ჩამოსული ზოგიერთი მწიგნობარი." },
  { verse: 2, text: "დაინახეს, რომ ზოგიერთი მისი მოწაფე ჭუჭყიანი, ესე იგი, დაუბანელი ხელით ჭამდა პურს, და დაჰგმეს ისინი." },
  { verse: 3, text: "(რადგან ფარისეველნი და, საერთოდ, იუდეველნი ისე არ ჭამენ პურს, თუ საგულდაგულოდ არ დაიბანეს ხელი, წინაპართა გადმოცემისამებრ." },
  { verse: 4, text: "არც მოედნებიდან დაბრუნებულნი ჭამენ დაუბანლად, და მრავალ სხვა წესსაც იცავენ, როგორიცაა მაგალითად, თასების, ჯამების, ქვაბებისა და ვარცლების რეცხვა)." },
  { verse: 5, text: "მაშინ ჰკითხეს მას ფარისევლებმა და მწიგნობრებმა: რატომ არ იქცევიან შენი მოწაფეები წინაპართა გადმოცემისამებრ, არამედ ხელდაუბანლად ჭამენ პურს?" },
  { verse: 6, text: "ხოლო იესომ პასუხად მიუგო მათ: მართლად იწინასწარმეტყველა თქვენებრ თვალთმაქცთათვის ესაია წინასწარმეტყველმა, ვის მიერაც დაიწერა: ეს ხალხი მადიდებს თავისი ბაგით, მაგრამ მისი გული შორსაა ჩემგან." },
  { verse: 7, text: "ამაოდ მადიდებენ, რადგან ასწავლიან ადამიანთა მოძღვრებებსა და მცნებებს." },
  { verse: 8, text: "ვინაიდან მიგიტოვებიათ ღმერთის მცნება და იცავთ კაცთა გადმოცემას, ჯამ-ჭურჭლის რეცხვას და სხვა მისთანათ." },
  { verse: 9, text: "და უთხრა მათ: მერედა, კარგია, რომ აუქმებთ ღმერთის მცნებას, რათა დაიცვათ თქვენი გადმოცემა?" },
  { verse: 10, text: "ვინაიდან მოსემ თქვა: პატივი ეცი მამას შენსას და დედას შენსას; და კიდევ: ვინც მამისა თუ დედის ძვირს იტყვის, სიკვდილით მოკვდეს." },
  { verse: 11, text: "ხოლო თქვენ ამბობთ: თუ კაცი ეტყვის მამას ან დედას: ღმერთს ვწირავ კორბანს, ანუ შესაწირავს, რაც ჩემგან უნდა მიგეღო, -" },
  { verse: 12, text: "ნებას რთავთ მას, აღარაფერი გააკეთოს თავისი დედ-მამისათვის." },
  { verse: 13, text: "და ამრიგად, თქვენგანვე მომდინარე გადმოცემით აუქმებთ ღმერთის სიტყვას და მრავალ ამნაირ რასმე სჩადიხართ." },
  { verse: 14, text: "მოუხმო ხალხს და უთხრა: მისმინეთ ყველამ და შეიმეცნეთ:" },
  { verse: 15, text: "არაფერი გარედან შემავალი არ ბილწავს კაცს, არამედ მისგან გამომავალია, რაც ბილწავს კაცს." },
  { verse: 16, text: "ვისაც ყური აქვს სმენად, ისმინოს:" },
  { verse: 17, text: "ხოლო, როცა ხალხს გაეცალა და სახლში შევიდა, მისმა მოწაფეებმა ჰკითხეს იგავის აზრი." },
  { verse: 18, text: "და უთხრა მათ: ნუთუ თქვენც არა გაგეგებათ რა? ნუთუ არ გესმით, რომ არაფერს, გარედან შემავალს კაცში, არ შეუძლია მისი შებილწვა?" },
  { verse: 19, text: "ვინაიდან მის გულში კი არ შედის, არამედ მუცელში, და გარეთ გამოდის, რითაც წმიდა იყოფა ყოველი საზრდო." },
  { verse: 20, text: "და თქვა: კაცისაგან გამომავალი შებილწავს კაცს." },
  { verse: 21, text: "ვინაიდან შიგნიდან, კაცის გულიდან გამოვლენ: ბოროტი ზრახვანი, მრუშობანი, პარვანი, კაცისკვლანი," },
  { verse: 22, text: "სიძვანი, ანგარებანი, უკეთურებანი, მზაკვრობანი, გარყვნილება, თვალის სიავე, გმობა, ქედმაღლობა, უგუნურება." },
  { verse: 23, text: "ყოველივე ეს შიგნიდან გამოდის და ბილწავს კაცს." },
  { verse: 24, text: "წამოვიდა იქიდან და მივიდა ტიროსისა და სიდონის საზღვარს. შევიდა სახლში და არ უნდოდა ვინმეს გაეგო ეს, მაგრამ ვერ შესძლო დაფარვა." },
  { verse: 25, text: "რადგან გაიგო ერთმა ქალმა, ვის ასულსაც უწმინდური სული ჰყავდა, მივიდა და ფეხქვეშ ჩაუვარდა მას." },
  { verse: 26, text: "ხოლო ეს ქალი წარმართი იყო. ტომით ასუროფინიკიელი, და შეევედრა, გაეძევებინა ეშმაკი მისი ასულისაგან." },
  { verse: 27, text: "მაგრამ იესომ უთხრა: მაცალე, ჯერ დავაძღო შვილები; სად გაგონილა, შვილებს წაართვა და ძაღლებს მიუგდო პური." },
  { verse: 28, text: "ქალმა პასუხად მიუგო: დიახ, უფალო; მაგრამ ძაღლებიც ხომ ჭამენ ტაბლის ქვეშ შვილების ნასუფრალს?" },
  { verse: 29, text: "და უთხრა მას: მაგ სიტყვისათვის წადი; გამოვიდა ეშმაკი შენი ასულისაგან." },
  { verse: 30, text: "მივიდა ქალი თავის სახლში და ნახა, რომ მისი ასული სარეცელზე იწვა, ეშმაკი კი გამოსულიყო მისგან." },
  { verse: 31, text: "მერე კვლავ წამოვიდა ტიროსისა და სიდონის საზღვრით და მოვიდა გალილეის ზღვის პირას, ათქალაქის საზღვართა შორის." },
  { verse: 32, text: "მიჰგვარეს მას ყრუ და ენაბლუ და შეევედრნენ, ხელი დაედო მისთვის." },
  { verse: 33, text: "ხალხს გააცალა, თითებით დაუცო ყური, გადააფურთხა და მის ენას შეეხო;" },
  { verse: 34, text: "ზეცად აღაპყრო თვალნი, ამოიოხრა და უთხრა მას: ეფფათა! რაც ნიშნავს: გაიხსენ!" },
  { verse: 35, text: "მაშინვე გაეხსნა სმენაცა და დაბმული ენაც და გამართულად ამეტყველდა." },
  { verse: 36, text: "და უბრძანა მათ, არავისთან გამამხილოთო, მაგრამ რაც უფრო მეტს უბრძანებდა, მით უფრო მეტად ამხელდნენ;" },
  { verse: 37, text: "დიდად უკვირდათ და ამბობდნენ: ყოველივეს კეთილად იქმს: ყრუს სმენას უბრუნებს და უტყვს ამეტყველებსო." },
],  
  8: [
  { verse: 1, text: "იმ დღეებში, როცა კვლავ დიდძალმა ხალხმა მოიყარა თავი და საჭმელი არა ჰქონდათ, იესომ უხმო თავის მოწაფეებს და უთხრა:" },
  { verse: 2, text: "მეცოდება ეს ხალხი, რადგან აგერ უკვე სამი დღეა ჩემთან არიან, და არაფერი აქვთ საჭმელი." },
  { verse: 3, text: "მშივრები რომ გავუშვა შინ, გზაში დაუძლურდებიან, ვინაიდან ზოგი მათგანი შორიდანაა მოსული." },
  { verse: 4, text: "მიუგეს მისმა მოწაფეებმა და უთხრეს: ვის შეუძლია აქ, ამ უდაბნოში, ამდენი ხალხის დაპურება?" },
  { verse: 5, text: "და ჰკითხა მათ: რამდენი პური გაქვთ? ხოლო მათ მიუგეს: შვიდი." },
  { verse: 6, text: "მაშინ მიწაზე დასხდომა უბრძანა ხალხს. აიღო შვიდი პური, აკურთხა, დატეხა და ჩამოსარიგებლად მისცა თავის მოწაფეებს; და მათაც ჩამოურიგეს ხალხს." },
  { verse: 7, text: "ცოტაოდენი თევზიც ჰქონდათ; ისიც აკურთხა და ბრძანა ჩამოერიგებინათ მათთვის." },
  { verse: 8, text: "ჭამეს და გაძღნენ; და გაავსეს ნარჩენებით შვიდი კალათი." },
  { verse: 9, text: "ხოლო იყო მჭამელი ოთხი ათასამდე კაცი; და გაისტუმრა ისინი." },
  { verse: 10, text: "თავისი მოწაფეებითურთ მაშინვე ჩაჯდა ნავში და მივიდა დალმანუთის მხარეს." },
  { verse: 11, text: "გამოვიდნენ ფარისევლები, დავა დაუწყეს და საცდუნებლად სასწაული მოსთხოვეს ზეცით." },
  { verse: 12, text: "მაშინ მძიმედ ამოიოხრა და თქვა: რად ეძებს ეს მოდგმა სასწაულს? ჭეშმარიტად გეუბნებით თქვენ: არ მიეცემა სასწაული ამ მოდგმას." },
  { verse: 13, text: "და მიატოვა ისინი, კვლავ ნავში ჩაჯდა და გაღმა გავიდა." },
  { verse: 14, text: "მოწაფეებს კი დაავიწყდათ პურის წაღება, და ერთი პურის მეტი არ ჰქონდათ ნავში." },
  { verse: 15, text: "უბრძანა მათ იესომ და უთხრა: ფხიზლად იყავით, ერიდეთ ფარისეველთა საფუარს და ჰეროდეს საფუარს." },
  { verse: 16, text: "ხოლო ისინი ერთმანეთში ბჭობდნენ: ალბათ, იმიტომ, პური რომ არ გვაქვსო." },
  { verse: 17, text: "მიუხვდა იესო და უთხრა მათ: რასა ბჭობთ, პური რომ არა გვაქვსო? ვერც რასა სცნობთ და არც რა გესმით? ნუთუ გაქვავდა თქვენი გული?" },
  { verse: 18, text: "თვალი გაქვთ და ვერას ხედავთ, ყური გაქვთ და არა გესმით რა და არც რა გახსოვთ?" },
  { verse: 19, text: "როგორ დავუტეხე ხუთი პური ხუთი ათას კაცს, და ნარჩენებით რამდენი კალათი დაავსეთ კიდევ? თქვეს: თორმეტი." },
  { verse: 20, text: "ანდა შვიდი - ოთხი ათასს, და რამდენი კალათი დაავსეთ კიდევ? მათ თქვეს: შვიდი." },
  { verse: 21, text: "და უთხრა მათ: ახლაც არ გესმით?" },
  { verse: 22, text: "მივიდნენ ბეთსაიდას, მიჰგვარეს ბრმა და შეევედრნენ, ხელი შეეხო მისთვის." },
  { verse: 23, text: "ხელი ჩაჰკიდა ბრმას, სოფლიდან გაიყვანა, თვალებზე მიაფურთხა, ხელი დაადო და ჰკითხა: ხედავ რასმე?" },
  { verse: 24, text: "მანაც გაიხედა და თქვა: ხალხს ვხედავ, თითქოს ხეები დადიანო." },
  { verse: 25, text: "მაშინ კვლავ დაადო ხელი თვალებზე და გაახელინა; დაუბრუნდა თვალის ჩინი და ყველაფერი ცხადად დაინახა." },
  { verse: 26, text: "გაგზავნა შინ და უთხრა: სოფელშიაც კი ნუ შეხვალ." },
  { verse: 27, text: "წავიდნენ იესო და მისი მოწაფეები ფილიპეს კესარიის სოფლებში, და გზაში ჰკითხა მათ: რას ამბობს ხალხი, ვინ ვგონივარ მე?" },
  { verse: 28, text: "ხოლო მათ მიუგეს: იოანე ნათლისმცემელი, ზოგს - ელია და ზოგსაც - ერთ-ერთი წინასწარმეტყველი." },
  { verse: 29, text: "კვლავ ჰკითხა მათ: თქვენ თვითონ ვინღა გგონივართ? მიუგო პეტრემ და უთხრა მას: შენა ხარ ქრისტე." },
  { verse: 30, text: "მაშინ უბრძანა მათ, არავისთან გაეთქვათ იგი." },
  { verse: 31, text: "და დაუწყო მათ სწავლება, რომ ძეს კაცისას ელოდა მრავალი ტანჯვის დათმენა, შეურაცხყოფა უხუცესთაგან, მღვდელმთავართა და მწიგნობართაგან, სიკვდილით დასჯა და მესამე დღეს აღდგომა." },
  { verse: 32, text: "აშკარად ამბობდა ამას. მაგრამ პეტრემ განზე გაიხმო და კიცხვა დაუწყო." },
  { verse: 33, text: "ხოლო ის მობრუნდა, გადახედა თავის მოწაფეებს, შერისხა პეტრე და უთხრა: გამშორდი, სატანა; ვინაიდან ღმერთისას კი არ ფიქრობ, არამედ კაცისას." },
  { verse: 34, text: "მოუხმო ხალხს თავის მოწაფეებთან ერთად და უთხრა მათ: ვისაც სურს მე მომდიოს, განუდგეს თავის თავს, აიღოს თავისი ჯვარი და გამომყვეს მე." },
  { verse: 35, text: "რადგან ვისაც სურს სულის ხსნა, დაჰკარგავს მას: და ვინც ჩემი და სახარების გულისთვის დაჰკარგავს სულს, ის ჰპოვებს მას." },
  { verse: 36, text: "რას არგებს კაცს, თუ მოიგებს მთელ ქვეყანას და სულს კი წააგებს?" },
  { verse: 37, text: "ანდა რას მისცემს კაცი თავისი სულის სანაცვლოდ?" },
  { verse: 38, text: "რადგან ვისაც ვერცხვინები მეცა და ჩემი სიტყვებიც ამ მემრუშე და ცოდვილ მოდგმაში, ძეც კაცისა სამარცხვინოდ მიიჩნევს მას, როდესაც მოვა მამის თვისის დიდებითა და წმიდა ანგელოზთა თანხლებით." },
],
9: [
  { verse: 1, text: "და უთხრა მათ: ჭეშმარიტად გეუბნებით თქვენ: ზოგი აქ მყოფთაგანი არ იგემებს სიკვდილს, სანამ არ იხილავს ღმრთის სასუფეველს, მომავალს ძალმოსილებით." },
  { verse: 2, text: "ექვსი დღის შემდეგ წაიყვანა იესომ პეტრე, იაკობი და იოანე, მარტო ისინი აიყვანა მაღაღ მთაზე და მათ წინაშე იცვალა ფერი." },
  { verse: 3, text: "სამოსი მისი გახდა მოელვარე და ისეთი სპეტაკი, როგორც ვერცერთი მრეცხავი ვერაფერს გაასპეტაკებს ამ ქვეყნად." },
  { verse: 4, text: "და მოევლინა მათ ელია და მოსე, იესოსთან მოსაუბრენი." },
  { verse: 5, text: "და უთხრა პეტრემ იესოს: რაბი! რა გვიჯობს აქ ყოფნას? მოდი, გავაკეთოთ სამი კარავი: ერთი - შენ, ერთი - მოსეს და ერთიც - ელიას." },
  { verse: 6, text: "რადგან არ იცოდა, რა ეთქვა, ვინაიდან შეშინებულნი იყვნენ." },
  { verse: 7, text: "გამოჩნდა ღრუბელი და ჩრდილით დაბურა ისინი. და გაისმა ხმა ღრუბლით, რთმელმაც თქვა: ეს არის ძე ჩემი საყვარელი: უსმინეთ მას." },
  { verse: 8, text: "იმწამსვე მიმოიხედეს, მაგრამ ვერავინ დაინახეს იესოს გარდა." },
  { verse: 9, text: "ხოლო მთიდან ჩამოსვლისას იესომ უბრძანა მათ, არავისთვის გაენდოთ ეს ხილვა, ვიდრე ძე კაცისა არ აღდგებთდა მკვდრეთით." },
  { verse: 10, text: "მათ დაიხსომეს ეს სიტყვა და ერთმანეთს ეკითხებთდნენ: რას ნიშნავს მკვდრეთით აღდგომა?" },
  { verse: 11, text: "და ჰკითხეს მას: რატომ ამბობენ მწიგნობარნი, პირველად ელია უნდა მოვიდესო?" },
  { verse: 12, text: "ხოლო მან პასუხად თქვა: მართალია, პირველად ელია უნდა მოვიდეს და აღადგინოს ყოველი. კაცის ძეს კი, როგორც დაიწერა მასზე, დიდი ტანჯვა და შეურაცხყოფა ელის." },
  { verse: 13, text: "მაგრამ გეუბნებით: ელია უკვე მოვიდა და როგორც უნდოდათ, ისე მოექცნენ; როგორც დაიწერა მისთვის." },
  { verse: 14, text: "როცა მოწაფეებთან დაბრუნდა, იხილა მათ ირგვლივ შეკრებილი დიდძალი ხალხი და მათთან მოკამათე მწიგნობრები." },
  { verse: 15, text: "მაშინვე შენიშნა მთელმა ხალხმა; განცვიფრებულნი გამოიქცნენ და მიესალმნენ." },
  { verse: 16, text: "ჰკითხა მწიგნობრებს: რას ედავებით ამათ?" },
  { verse: 17, text: "ერთმა კაცმა ხალხიდან მიუგო მას: მოძღვარო, ჩემი ძე მოგგვარე, შეპყრობილი სიმუნჯის სულით." },
  { verse: 18, text: "სადაც მოიხელთებს, ძირს დასცემს; დუჟი გადმოსდის, კბილებს აღრჭიალებს და შეშდება. ვთხოვე შენს მოწაფეებს, განდევნეთ-მეთქი, მაგრამ ვერ შესძლეს." },
  { verse: 19, text: "ხოლო იესომ პასუხად თქვა: ო, ურწმუნო მოდგმავ, როდემდის ვიქნები თქვენთან? როდემდის მოგითმენთ თქვენ? აქ მომგვარეთ!" },
  { verse: 20, text: "მიჰგვარეს იგი, და იხილა თუ არა იესო, სულმა შეარყია ბავშვი, მიწაზე დაეცა და გორავდა დუჟმორეული." },
  { verse: 21, text: "ჰკითხა მამამისს: რამდენი ხანია ასე? ხოლო მან მიუგო: სიყრმითგანვე." },
  { verse: 22, text: "მრავალჯერ ჩაუგდია სულს ცეცხლსა თუ წყალში, რათა დაეღუპა იგი. მაშ, თუ რამ შეგიძლია, შეგვიწყალე და შეგვეწიე." },
  { verse: 23, text: "ხოლო იესომ უთხრა მას: თუ შეგიძლია გწამდეს, ყველაფერი შესაძლოა მორწმუნისათვის." },
  { verse: 24, text: "ბავშვის მამამ მყისვე შეჰღაღადა ცრემლების ფრქვევით: მწამს, უფალო; შეეწიე ჩემს ურწმუნოებას." },
  { verse: 25, text: "როდესაც დაინახა იესომ, რომ ხალხი ეხვევა გარშემო, შერისხა სული და უთხრა: ყრუ-მუნჯო სულო! გიბრძანებ გამოხვიდე მაგისგან და აღარასოდეს შეხვიდე მასში!" },
  { verse: 26, text: "სულმა შეჰყვირა, საშინლად შეარყია იგი და გამოვიდა, ხოლო ბავშვი მკვდარს დაემსგავსა; ასე რომ, ბევრი ამბობდა კიდეც: მოკვდაო." },
  { verse: 27, text: "მაგრამ იესომ ხელი მოჰკიდა, წამოაყენა და ისიც აღდგა." },
  { verse: 28, text: "როდესაც სახლში შევიდა, მისმა მოწაფეებმა განცალკევებით ჰკითხეს: რატომ ჩვენ ვერ შევძელით მისი განდევნა?" },
  { verse: 29, text: "და უთხრა მათ: ამ მოდგმას ვერაფრით ვერ განდევნი, თუ არა ლოცვით და მარხვით." },
  { verse: 30, text: "წამოვიდა იქიდან, გალილეა გადაიარა და არ უნდოდა ვინმეს გაეგო ეს." },
  { verse: 31, text: "ვინაიდან ასწავლიდა თავის მიწაფეებს და ეუბნებოდა მათ, რომ ძე კაცისა მიეცემა კაცთა ხელში, მოკლავენ მას და, სიკვდილის შემდეგ, მესამე დღეს აღდგება მკვდრეთით." },
  { verse: 32, text: "მაგრამ მათ ვერ გაიგეს ეს სიტყვები, კითხვა კი ვერ შეჰბედეს." },
  { verse: 33, text: "მივიდა კაპერნაუმში; და სახლში ყოფნისას ჰკითხა მათ: რაზე მსჯელობდით გზაში?" },
  { verse: 34, text: "ისინი კი დუმდნენ, ვინაიდან გზაში იმაზე ბჭობდნენ, ვინ უფრო დიდიაო." },
  { verse: 35, text: "მაშინ დაჯდა, მოუხმო თორმეტს და უთხრა მათ: ვისაც სურს პირველი იყოს, ყველაზე უკანასკნელი იქნება და ყველას მსახური." },
  { verse: 36, text: "მოიყვანა პატარა ბავშვი, მათ შორის ჩააყენა, ხელი მოხვია და უთხრა მათ:" },
  { verse: 37, text: "ვინც შეიწყნარებს ერთ ამნაირ ბავშვს ჩემი სახელით, მე შემიწყნარებს, ხოლო ჩემი შემწყნარებელი მე კი არ შემიწყნარებს, არამედ ჩემს მომავლინებელს." },
  { verse: 38, text: "მიუგო იოანემ და უთხრა მას: მოძღვარო, ვიხილეთ კაცი, რომელიც შენი სახელით აძევებს ეშმაკთ და ჩვენ კი არ მოგვდევს; და ავუკრძალეთ იმიტომ, რომ ჩვენ არ მოგვყვება." },
  { verse: 39, text: "ხოლო იესომ თქვა: ნუ უკრძალავთ, რადგან ვერავინ, ვინც ჩემი სახელით ახდენს სასწაულს, აგრე იოლად ვერ იტყვის ჩემს ძვირს." },
  { verse: 40, text: "რადგან ვინც ჩვენს წინააღმდეგ არაა, ჩვენს მხარესაა." },
  { verse: 41, text: "იმას, ვინც ჭიქა წყალს მოგაწვდით ჩემი სახელით, ვინაიდან ქრისტესი ხართ, ჭეშმარიტად გეუბნებით: არ დაეკარგება თავისი საზღაური." },
  { verse: 42, text: "და ვინც აცთუნებს თუნდაც ერთ ამ მცირეთაგანს, რომელსაც მე ვწამვარ, უჯობს წისქვილის დოლაბი დაჰკიდონ ყელზე და ზღვაში დანთქან." },
  { verse: 43, text: "თუ შენი ხელი გაცთუნებს, მოიკვეთე იგი: გიჯობს სახიჩარი შეხვიდე სიცოცხლეში, ვიდრე ორივე ხელის მქონე ჩავარდე გეენაში, გაუნელებელ ცეცხლში," },
  { verse: 44, text: "სადაც ულევია მათთვის მატლი და უშრეტი - ცეცხლი." },
  { verse: 45, text: "თუ შენი ფეხი გაცთუნებს, მოიკვეთე იგი: გიჯობს კოჭლი შეხვიდე სიცოცხლეში, ვიდრე ორივე ფეხის მქონე ჩავარდე გეენაში, გაუნელებელ ცეცხლში," },
  { verse: 46, text: "სადაც ულევია მათთვის მატლი და უშრეტი - ცეცხლი." },
  { verse: 47, text: "ხოლო თუ შენი თვალი გაცთუნებს, ამოითხარე იგი: გიჯობს ცალთვალა შეხვიდე ღმრთის სასუფეველში, ვიდრე ორივე თვალის მქონე ჩავარდე ცეცხლის გეენაში," },
  { verse: 48, text: "სადაც ულევია მათთვის მატლი და უშრეტი - ცეცხლი." },
  { verse: 49, text: "რადგან ყველაფერი ცეცხლით დამარილდება და ყოველი შესაწირავი მარილით დამარილდება." },
  { verse: 50, text: "კარგი რამ არის მარილი; მაგრამ თუ მარილი უმარილო გახდა, რაღათი შეანელებთ მას? გქონდეთ მარილი თქვენში და მშვიდობით იყავით ერთმანეთს შორის." },
],
10: [
  { verse: 1, text: "წამოვიდა იქიდან და მივიდა იუდეის მხარეში, იორდანეს გაღმა. კვლავ მიაშურა მას ხალხმა და, როგორც სჩვეოდა, კვლავ ასწავლიდა მათ." },
  { verse: 2, text: "მიადგნენ ფარისევლები და საცდუნებლად ჰკითხეს: აქვს თუ არა ქმარს ცოლის გაშვების ნება?" },
  { verse: 3, text: "ხოლო მან პასუხად თქვა: რა გამცნოთ მოსემ?" },
  { verse: 4, text: "მათ მიუგეს: მოსემ ჩვენ დაგვრთო გაყრის წერილის დაწერისა და გაშვების ნება." },
  { verse: 5, text: "იესომ პასუხად უთხრა მათ: თქვენი გულქვაობის გამო მოგცათ ეს მცნება." },
  { verse: 6, text: "შექმნის დასაბამიდან კი კაცად და ქალად შექმნა ისინი ღმერთმა." },
  { verse: 7, text: "ამიტომ მიატოვებს კაცი მამას თავისას და დედას," },
  { verse: 8, text: "და შეერთვის თავის ცოლს, და იქნებიან ორივენი ერთ ხორც. ასე რომ, ორნი კი აღარ არიან, არამედ ერთ ხორც." },
  { verse: 9, text: "ამრიგად, ვინც ღმერთმა შეაუღლა, დაე, ნუ განაშორებს კაცი." },
  { verse: 10, text: "სახლში მისმა მოწაფეებმა კვლავ ჰკითხეს იგივე." },
  { verse: 11, text: "და უთხრა მათ: ვინც გაუშვებს თავის ცოლს და სხვას შეირთავს, მის მიმართ მრუშობს." },
  { verse: 12, text: "ხოლო თუ ცოლი გაეყრება თავის ქმარს და სხვას გაჰყვება, მრუშობს." },
  { verse: 13, text: "მიჰგვარეს მას ბავშვები, რათა ხელი დაედო მათთვის; მოწაფეები კი არ უშვებდნენ მომგვრელთ." },
  { verse: 14, text: "ეს რომ დაინახა, განრისხდა და უთხრა მათ: მოუშვით ჩემთან ბავშვები და ნუ უშლით მათ, ვინაიდან მათნაირებისაა ღმრთის სასუფეველი." },
  { verse: 15, text: "ჭეშმარიტად გეუბნებით თქვენ: ვინც ბავშვივით არ მიიღებს ღმრთის სასუფეველს, ვერ შევა მასში." },
  { verse: 16, text: "მოეხვია, ხელი დაადო და დალოცა ისინი." },
  { verse: 17, text: "გზას რომ დაადგა, ვიღაცამ მოირბინა, მუხლი მოიყარა მის წინაშე და უთხრა: კეთილო მოძღვარო, რა ვქნა, რომ დავიმკვიდრო საუკუნო სიცოცხლე?" },
  { verse: 18, text: "იესომ მიუგო: რატომ მიწოდებ კეთილს? არავინაა კეთილი, გარდა ერთის - ღმრთისა." },
  { verse: 19, text: "იცი მცნებანი: არა იმრუშო; არა კაც-ჰკლა; არა იპარო; არა ცილი სწამო; არა შეურაცხყო; პატივი ეცი მამას შენსას და დედას?" },
  { verse: 20, text: "ხოლო მან პასუხად უთხრა: მოძღვარო, ეს ყოველივე დამიცავს ჩემი სიყრმიდან." },
  { verse: 21, text: "იესომ შეხედა, მოეწონა და უთხრა: ერთიღა გაკლია: წადი, გაყიდე ყველაფერი, რაც გაბადია, მიეცი გლახაკთ და გექნება საუნჯე ცაში; მერე მოდი და გამომყევ მე." },
  { verse: 22, text: "ხოლო ის შეაკრთო ამ სიტყვამ და დამწუხრებული წავიდა, რადგანაც ძალიან მდიდარი იყო." },
  { verse: 23, text: "მიმოიხედა იესომ და თავის მოწაფეებს უთხრა: რარიგ ძნელია მდიდრისათვის ღმრთის სასუფეველში შესვლა." },
  { verse: 24, text: "მოწაფეებს გაუკვირდათ ეს სიტყვები, ხოლო მან ხელახლა მიუგო და უთხრა მათ: შვილებო, რარიგ ძნელია სიმდიდრის მოყვარულთათვის ღმრთის სასუფეველში შესვლა." },
  { verse: 25, text: "აქლემი უფრო ადვილად გაძვრება ნემსის ყუნწში, ვიდრე მდიდარი შევა ღმრთის სასუფეველში." },
  { verse: 26, text: "ხოლო მათ უფრო უკვირდათ, და ერთმანეთს ეკითხებოდნენ: კი მაგრამ, ვინღა ცხონდება?" },
  { verse: 27, text: "იესომ შეხედა და უთხრა მათ: კაცთათვის ეს შეუძლებელია, მაგრამ არა ღმრთისთვის; ვინაიდან ყველაფერი შესაძლებელია ღმრთისთვის." },
  { verse: 28, text: "დაიწყო პეტრემ და უთხრა მას: აი, ჩვენ მივატოვეთ ყველაფერი და შენ გამოგყევით." },
  { verse: 29, text: "იესომ პასუხად თქვა: ჭეშმარიტად გეუბნებით თქვენ: არ არის კაცი, რომელმაც მიატოვოს სახლ-კარი, გინდა და-ძმები, გინდა დედ-მამა, გინდა ცოლ-შვილი, გინდა ადგილ-მამული ჩემი და სახარების გულისთვის," },
  { verse: 30, text: "და ახლავე, ამჟამად, ასმაგად არ მიიღოს სახლ-კარიც, და-ძმაც, დედ-მამაც, შვილებიც და ადგილ-მამულიც, ხოლო მომავალ საუკუნეში - საუკუნო სიცოცხლე." },
  { verse: 31, text: "მაგრამ მრავალი პირველი იქნება უკანასკნელი, და მრავალი უკანასკნელი - პირველი." },
  { verse: 32, text: "როდესაც იერუსალიმისაკენ მიმავალ გზას ადგნენ, იესო წინ მიუძღოდა მათ, ხოლო მისი მიმდევრები გაკვირვებულნი და შეშინებულნი იყვნენ. კვლავ მოიხმო თორმეტი და დაუწყო ლაპარაკი იმაზე, თუ რა ელოდა მას:" },
  { verse: 33, text: "აჰა, ავდივართ იერუსალიმს, და ძე კაცისა მიეცემა მღვდელმთავრებსა და მწიგნობრებს, მიუსჯიან მას სიკვდილს და მისცემენ წარმართთ." },
  { verse: 34, text: "შეურაცხყოფენ, სცემენ აფურთხებენ და მოკლავენ; მესამე დღეს კი აღდგება იგი." },
  { verse: 35, text: "მაშინ მივიდნენ მასთან ზებედეს ძენი - იაკობი და იოანე და უთხრეს: მოძღვარო, გვსურს შეგვისრულო, რასაცა გთხოვთ." },
  { verse: 36, text: "იესომ ჰკითხა მათ: მაინც რის შესრულებას მთხოვთ?" },
  { verse: 37, text: "მათ მიუგეს: მოგვეცი ნება, რათა შენს დიდებაში ერთი შენს მარჯვნივ და მეორე შენს მარცხნივ დავსხდეთ." },
  { verse: 38, text: "მაგრამ იესომ პასუხად თქვა: არ იცით, რას ითხოვთ. შეგიძლიათ შესვათ სასმისი, რომლითაც მე ვსვამ, და ნათლობით, რომლითაც მე ვინათლები, მოინათლოთ?" },
  { verse: 39, text: "მათ თქვეს: შეგვიძლია, ხოლო იესომ მიუგო მათ: სასმისს, რომლითაც მე ვსვამ, შესვამთ, და ნათლობით, რომლითაც მე ვინათლები, მოინათლებით." },
  { verse: 40, text: "მაგრამ მე როდი მომეცა, თუ ვინ დაჯდება ჩემს მარჯვნივ, და ვინ - მარცხნივ, არამედ ვისთვისაც გამზადებულია ეს." },
  { verse: 41, text: "ამის მოსმენისას ათი მოწაფე რისხვით აღივსო იაკობისა და იოანეს მიმართ." },
  { verse: 42, text: "ხოლო იესომ მიიხმო ისინი და უთხრა მათ: თქვენ იცით, რომ ხალხთა მთავრებად მიჩნეულნი მბრძანებლობენ მათზე და დიდებულნი ძალადობით განაგებენ მათ." },
  { verse: 43, text: "ხოლო თქვენს შორის ნუ იქნება ასე, არამედ ვინც თქვენში მოისურვებს უფროსობას, ის იყოს თქვენი მსახური." },
  { verse: 44, text: "და ვინც თქვენში მოისურვებს პირველობას, ის იყოს ყველას მონა." },
  { verse: 45, text: "რადგან ძე კაცისა იმისთვის კი არ მოვიდა, რომ სხვები იმსახუროს, არამედ რათა სხვებს ემსახუროს, და მისცეს თავისი სული მრავალთა გამოსახსნელად." },
  { verse: 46, text: "მივიდნენ იერიხონში, და როდესაც გამოდიოდა იერიხონიდან, თავის მოწაფეებსა და დიდძალ ხალხთან ერთად, ტიმეოსის ძე, ბრმა ბარტიმეოსი, გზის პირას იჯდა მოწყალების მთხოვნელად." },
  { verse: 47, text: "როცა გაიგონა, იესო ნაზარეველიაო, ყვირილი მორთო: იესო, დავითის ძეო, შემიწყალე მე!" },
  { verse: 48, text: "ბევრი რისხავდა, გაჩუმდით, მაგრამ ის უფრო ხმამაღლა ყვიროდა, დავითის ძეო, შემიწყალე მე!" },
  { verse: 49, text: "იესო შეჩერდა და ბრძანა, დაუძახეთო; დაუძახეს ბრმას და უთხრეს: ნუ გეშინია, ადექ, გეძახის." },
  { verse: 50, text: "მანაც დააგდო თავისი მოსასხამი, ადგა და იესოსთან მივიდა." },
  { verse: 51, text: "იესომ ჰკითხა: რას მოითხოვ ჩემგან? ხოლო ბრმამ მიუგო: რაბუნი, თვალის ახელას!" },
  { verse: 52, text: "იესომ უთხრა მას: წადი, შენმა რწმენამ გადაგარჩინა. მაშინვე აეხილა თვალი და გზად გაჰყვა იესოს." },
],
11: [
  { verse: 1, text: "როდესაც მიუახლოვდნენ იერუსალიმს, ბეთბაგეს და ბეთანიას, ზეთისხილის მთასთან, გაგზავნა თავისი ორი მოწაფე" },
  { verse: 2, text: "და უთხრა მათ: წადით სოფელში, რომელიც თქვენს პირდაპირაა და შესვლისთანავე იპოვით დაბმულ ჩოჩორს, რომელზედაც ჯერ კაცი არ მჯდარა; ახსენით და მომგვარეთ." },
  { verse: 3, text: "ხოლო თუ ვინმე გეტყვით, რას შვრებითო, უთხარით, უფალს სჭირდება და მალე დაგიბრუნებსო." },
  { verse: 4, text: "ისინი წავიდნენ, დაინახეს ქუჩაში ჭიშკართან დაბმული ჩოჩორი და ახსნეს იგი." },
  { verse: 5, text: "ზოგიერთმა იქ მდგომმა ჰკითხა მათ: რას შვრებით, რატომ ხსნით ჩოჩორს?" },
  { verse: 6, text: "მათ მიუგეს, როგორც უბრძანა იესომ, და გამოუშვეს ისინი." },
  { verse: 7, text: "მიჰგვარეს ჩოჩორი იესოს, ზურგზე დაუფინეს თავიანთი სამოსელი და ზედ შესვეს იგი." },
  { verse: 8, text: "ბევრი თავის სამოსელს უფენდა გზაზე, სხვები კი - ხის ტოტებს, რომლებსაც მინდვრად ჭრიდნენ." },
  { verse: 9, text: "წინ მიმავალნიცა და უკან მიმყოლნიც ღაღადებდნენ და ამბობდნენ: ოსანა! კურთხეულია მომავალი უფლის სახელით." },
  { verse: 10, text: "კურთხეულია დავითის, ჩვენი მამის, მომავალი სამეფო! ოსანა მაღალთა შინა!" },
  { verse: 11, text: "შევიდა იესო იერუსალიმსა და ტაძარში; როდესაც მოიხილა ყველაფერი, უკვე გვიანი იყო და ბეთანიას გაემართა თორმეტის თანხლებით." },
  { verse: 12, text: "ხოლო მეორე დღეს, ბეთანიიდან წამოსულს მოშივდა;" },
  { verse: 13, text: "შორიდან დაინახა გაფოთლილი ლეღვის ხე და მივიდა, იქნებ ზედ რამე ვიპოვოო, მაგრამ მისულმა ვერაფერი ნახა ფოთლების გარდა, ვინაიდან ჯერ კიდევ არ მოეწია ლეღვის მწიფობას." },
  { verse: 14, text: "და უთხრა მას: აღარავის ეგემოს შენი ნაყოფი უკუნისამდე! და გაიგონეს ეს მისმა მოწაფეებმა." },
  { verse: 15, text: "მივიდნენ იერუსალიმში; შევიდა იესო ტაძრად, და დაიწყო იმათი გამოყრა, ვინც ყიდიდა და ყიდულობდა ტაძარში; ააყირავა მეკერმეთა დახლები და მტრედებით მოვაჭრეთა მერხები." },
  { verse: 16, text: "და არავის აძლევდა იმის ნებას, რომ რამე გამოეტარებინა ტაძარში." },
  { verse: 17, text: "ასწავლიდა მათ და ამბობდა: განა დაწერილი არ არის, რომ ჩემი სახლი სალოცავ სახლად იწოდება ყველა ხალხისთვის? თქვენ კი ყაჩაღთა ბუნაგად გიქცევიათ იგი." },
  { verse: 18, text: "გაიგონეს ეს მწიგნობრებმა და მღვდელმთავრებმა და ეძებდნენ ხერხს მის დასაღუპად, რადგანაც ეშინოდათ მისი, ვინაიდან მთელ ხალხს უკვირდა მისი მოძღვრება." },
  { verse: 19, text: "შებინდებისას ქალაქიდან გამოვიდა." },
  { verse: 20, text: "დილაადრიან გვერდით ჩაუარეს და დაინახეს, რომ ლეღვის ხე ძირფესვიანად გამხმარიყო." },
  { verse: 21, text: "გაახსენდა პეტრეს და უთხრა მას: რაბი! შეხედე, ლეღვის ხე, შენ რომ დასწყევლე, გამხმარა." },
  { verse: 22, text: "მიუგო იესომ და უთხრა მათ: გქონდეთ ღმრთის რწმენა." },
  { verse: 23, text: "რადგან ჭეშმარიტად გეუბნებით თქვენ: თუ ვინმე ეტყვის ამ მთას: აღმოიფხვერი და ზღვაში ჩავარდიო, და არ შეეჭვდება თავის გულში, არამედ იწამებს, რომ მისი სიტყვისამებრ მოხდება, - ექნება ის, რასაც იტყვის." },
  { verse: 24, text: "ამიტომ გეუბნებით თქვენ: რასაც ლოცვაში ითხოვთ, გწამდეთ, ყველაფერს მიიღებთ და მოგეცემათ." },
  { verse: 25, text: "როდესაც ლოცვად დგახართ, მიუტევეთ, ვინც რამე გცოდათ, რათა მამამ თქვენმა ზეციერმაც მოგიტევოთ თქვენი შეცოდებანი." },
  { verse: 26, text: "ხოლო თუ არ მიუტევებთ, არც მამა თქვენი ზეციერი მოგიტევებთ თქვენს შეცოდებებს." },
  { verse: 27, text: "კვლავ მივიდნენ იერუსალიმში და როცა ტაძრად მიმოდიოდა, მიუახლოვდნენ მღვდელმთავარნი, მწიგნობარნი და უხუცესნი." },
  { verse: 28, text: "და უთხრეს მას: რომელი ძალით იქმ ამას? ან ვინ მოგცა ამისი ძალა?" },
  { verse: 29, text: "ხოლო იესომ მიუგო და უთხრა მათ: მეც ერთ რამეს გკითხავთ, და მიპასუხეთ: მაშინ გეტყვით, რომელი ძალით ვიქმ ამას." },
  { verse: 30, text: "ნათლისცემა იოანესი ზეციდან იყო თუ კაცთაგან? მიპასუხეთ." },
  { verse: 31, text: "ხოლო ისინი ერთმანეთში ბჭობდნენ: თუ ვეტყვით: ზეციდანო, ის გვეტყვის, მაშინ რატომ არ ერწმუნეთ მას?" },
  { verse: 32, text: "ხოლო თუ იტყოდნენ: კაცთაგანო, ხალხისა ეშინოდათ, ვინაიდან ყველას ჭეშმარიტ წინასწარმეტყველად მიაჩნდა იოანე." },
  { verse: 33, text: "ამიტომ პასუხად უთხრეს იესოს: არ ვიცით. ხოლო იესომ მიუგო მათ: მაშინ არც მე გეტყვით, რომელი ძალით ვიქმ ამას." },
],
12: [
  { verse: 1, text: "და დაუწყო მათ იგავებით ლაპარაკი: ერთმა კაცმა ჩაყარა ვაზი, შემოღობა, ამოკვეთა საწნახელი, ააგო კოშკი და იჯარით მისცა მევენახეებს, თვითონ კი წავიდა." },
  { verse: 2, text: "როცა დრომ მოაწია, მევენახეებთან გაგზავნა მონა, რათა მოსავალი ჩაებარებინა მათგან." },
  { verse: 3, text: "ხოლო მათ შეიპყრეს იგი, სცემეს და ხელცარიელი გაუშვეს." },
  { verse: 4, text: "კვლავ გაგზავნა მეორე მონა; მას ქვებით გაუტეხეს თავი და შეგინებული გააგდეს." },
  { verse: 5, text: "ახლა სხვა მონა გაგზავნა; ის კიდევ მოკლეს; და სხვასაც მრავალს ან სცემდნენ, ან კლავდნენ." },
  { verse: 6, text: "ერთი საყვარელი ძეც ჰყავდა; ბოლოს ის გაგზავნა მათთან, რადგან ეგონა, ჩემი ძის მაინც მოერიდებათო." },
  { verse: 7, text: "მაგრამ მევენახეებმა ერთმანეთს უთხრეს: აგერ მემკვიდრე; მოდით, მოვკლათ და მისი სამკვიდრთ ჩვენ დაგვრჩებაო." },
  { verse: 8, text: "შეიპყრეს იგი, მოკლეს და ვენახს გარეთ დააგდეს." },
  { verse: 9, text: "მერედა, რას იზამს ვენახის პატრონი? მოვა და დახოცავს მევენახეებს, ხოლო ვენახს სხვებს მისცემს." },
  { verse: 10, text: "ნუთუ არ ამოგიკითხავთ წერილში: ქვა, რომელიც დაიწუნეს მშენებლებმა, კუთხის თავად დაიდვა?" },
  { verse: 11, text: "უფლის მიერ იქმნა ეს, და საოცრებად უჩანს ჩვენს თვალს." },
  { verse: 12, text: "უნდოდათ მისი შეპყრობა, ვინაიდან მიხვდნენ, რომ მათზე ამბობდა იგავს; მაგრამ ხალხისა შეეშინდათ, მიატოვეს და გაეცალნენ." },
  { verse: 13, text: "მიუგზავნეს ზოგიერთი ფარისეველი და ჰეროდელი, რათა სიტყვის მახე დაეგოთ მისთვის." },
  { verse: 14, text: "მივიდნენ ისინი და უთხრეს: მოძღვარო, ვიცით, რომ მართალი ხარ, და არავის არჩევ, ვინაიდან არ უყურებ სახეს კაცისას, არამედ სამართლით გვასწავლი ღმრთის გზას. გვმართებს თუ არა ხარკი ვაძლიოთ კეისარს? ვაძლიოთ თუ არ ვაძლიოთ?" },
  { verse: 15, text: "ხოლო იესომ შეიცნო მათი თვალთმაქცობა და უთხრა მათ: რატომ მაცდუნებთ? მომიტანეთ დინარი, რათა ჩემი თვალით ვიხილო." },
  { verse: 16, text: "მიუტანეს თუ არა, უთხრა მათ: ვისია ეს ხატი და ეს წარწერა? მიუგეს: კეისრისა." },
  { verse: 17, text: "იესომ მიუგთ და უთხრა მათ: მიაგეთ კეისარს კეისრისა, ხოლო ღმერთს - ღმრთისა. და უკვირდათ მისი." },
  { verse: 18, text: "მერე მიუახლოვდნენ სადუკევეღნი, რომელნიც ამბობენ, რომ არ არსებობს აღდგომა, და ჰკითხეს:" },
  { verse: 19, text: "მოძღვარო, მოსემ დაგვიწერა, თუ ვინმეს მოუკვდება ძმა, რომელსაც დარჩება ცოლი, მაგრამ არ დარჩება შვილი, დაე, მისმა ძმამ მოიყვანოს მისი ცოლი, რათა აღუდგინოს თავის ძმას მისი თესლი." },
  { verse: 20, text: "იყო შვიდი ძმა; პირველმა შეირთო ცოლი და უშვილოდ მოკვდა." },
  { verse: 21, text: "მეორემ შეირთო იგი და ისიც უშვილოდ მოკვდა. ასევე მესამეც." },
  { verse: 22, text: "შვიდივეს ცოლად ჰყავდა და არცერთს არ დარჩა შვილი. ყველაზე ბოლოს კი ქალიც მოკვდა." },
  { verse: 23, text: "მერედა, აღდგომისას, როცა აღდგებიან, ვისი ცოლი იქნება იგი? ვინაიდან შვიდივეს ცოლად ესვა." },
  { verse: 24, text: "იესომ პასუხად მიუგო მათ: იმიტომ ხომ არ სცდებით, რომ არც წერილს იცნობთ და არც ღმრთის ძალას?" },
  { verse: 25, text: "რადგან მკვდრეთით აღდგომისას არც ცოლს ირთავენ და არც თხოვდებიან, არამედ არიან, როგორც ანგელოზები ცაში." },
  { verse: 26, text: "ხოლო მკვდართა აღდგომისათვის არ წაგიკითხავთ მოსეს წიგნში, რა უთხრა მას მაყვლოვანში ღმერთმა: მე ვარ ღმერთი აბრაამისა, ღმერთი ისააკისა და ღმერთი იაკობისა." },
  { verse: 27, text: "ღმერთი მკვდრებისა კი არ არის, არამედ - ცოცხლებისა. ხოლო თქვენ დიდად სცდებით." },
  { verse: 28, text: "მოვიდა ერთი მწიგნობართაგანი, რომელმაც გაიგონა მათი კამათი და მიხვდა, რომ კარგად მიუგო მათ, და ჰკითხა იესოს: რომელია უპირველესი მცნება?" },
  { verse: 29, text: "ხოლო იესომ მიუგო მას: აი, უპირველესი მცნება: ისმინე, ისრაელ! უფალი ღმერთი ჩვენი ერთი უფალია!" },
  { verse: 30, text: "და: გიყვარდეს უფალი ღმერთი შენი მთელი შენი გულით და მთელი შენი სულით და მთელი შენი გონებით და მთელი შენი ძალით, - აი, უპირველესი მცნება." },
  { verse: 31, text: "და მეორე, ამისი მსგავსი: გიყვარდეს მოყვასი შენი, ვითარცა თავი შენი. არ არსებობს ამათზე დიადი მცნება." },
  { verse: 32, text: "მწიგნობარმა უთხრა მას: კეთილი, მოძღვარო; ჭეშმარიტს ამბობ, რომ ერთია ღმერთი, და არ არის სხვა, მის გარდა;" },
  { verse: 33, text: "და რომ უნდა გვიყვარდეს იგი მთელი გულით და მთელი სულით და მთელი გონებით და მთელი ძალით; და გვიყვარდეს მოყვასი, როგორც საკუთარი თავი - ეს ყოველგვარ მსხვერპლსა და შესაწირავზე უმეტესია." },
  { verse: 34, text: "როცა იხილა იესომ, რომ გონივრულად უპასუხა, მიუგო მას: შორს როდი ხარ ღმრთის სასუფევლისგან. ამის შემდეგ ვეღარავინ ბედავდა რაიმე ეკითხა მისთვის." },
  { verse: 35, text: "კვლავ ასწავლიდა იესო ტაძარში და თქვა: როგორ ამბობენ მწიგნობრები, რომ ქრისტე დავითის ძეა?" },
  { verse: 36, text: "რადგან თვით დავითი ამბობს სულით წმიდით: უთხრა უფალმა ჩემს უფალს: დაჯექ ჩემს მარჯვნივ, ვიდრე ფერხთით დაგიმხობ მტრებს." },
  { verse: 37, text: "ამრიგად, თვით დავითი უწოდებს მას უფალს; როგორღა ეკუთვნის ძედ? დიდძალი ხალხი სიამოვნებით უსმენდა მას." },
  { verse: 38, text: "და თავისი სწავლით ამბობდა: ეკრძალეთ მწიგნობრებს, რომლებსაც უყვართ გრძელი სამოსით მოკაზმვა და საკრებულოებში - სალმის ძღვნა," },
  { verse: 39, text: "სინაგოგებში - წინა რიგები და წვეულებებზე - სუფრის თავში ჯდომა." },
  { verse: 40, text: "რომლებიც ნთქამენ ქვრივთა სახლებს და თვალთმაქცურად ლოცულობენ დიდხანს: მით უფრო მძიმე იქნება მათი სასჯელი." },
  { verse: 41, text: "დაჯდა იესო საგანძურის წინ და უყურებდა, როგორ ყრიდა ხალხი ფულს საგანძურში. ხოლო ბევრი მდიდარი ბლომად ყრიდა." },
  { verse: 42, text: "მოვიდა ერთი საწყალი ქვრივი ქალი და ჩააგდო ორი ლეპტა, რაც შეადგენს კოდრანტს." },
  { verse: 43, text: "მოუხმო თავის მოწაფეებს და უთხრა მათ: ჭეშმარიტად გეუბნებით თქვენ, რომ ამ საწყალმა ქვრივმა ყველაზე მეტი ჩააგდო საგანძურში." },
  { verse: 44, text: "ვინაიდან ყველა აგდებდა იმას, რაც ზედმეტი ჰქონდა, ხოლო მან ჩააგდო მთელი თავისი სისაწყლე, მთელი თავისი საბადებელი." },
],
13: [
  { verse: 1, text: "ტაძრიდან რომ გამოდიოდა, ერთმა მოწაფეთაგანმა უთხრა: მოძღვარო, შეხედე, რა ქვებია და რა შენობები!" },
  { verse: 2, text: "მიუგო იესომ და უთხრა მას: ხედავ ამ დიდებულ შენობებს? ქვა ქვაზეც არ დარჩება აქ, არამედ ყველაფერი დაინგრევა." },
  { verse: 3, text: "ხოლო როცა ზეთისხილის მთაზე, ტაძრის პირდაპირ იჯდა, განცალკევებით ჰკითხეს მას პეტრემ და იაკობმა, იოანემ და ანდრიამ:" },
  { verse: 4, text: "გვითხარი, როდის მოხდება ეს, ან იქნება ნიშანი იმისა, რომ ყოველივე ეს აღსრულდება?" },
  { verse: 5, text: "მიუგო იესომ და უთხრა მათ: ფხიზლად იყავით, რათა არავინ გაცდუნოთ." },
  { verse: 6, text: "ვინაიდან მრავალნი მოვლენ ჩემი სახელით, და იტყვიან: მე ვარო, და მრავალს აცდუნებენ." },
  { verse: 7, text: "ხოლო როდესაც გაიგებთ ომებსა და ომების ამბავს, ნუ შეძრწუნდებით, ვინაიდან ყოველივე ეს უნდა მოხდეს, მაგრამ ეს ჯერ კიდევ არ არის დასასრული." },
  { verse: 8, text: "რადგან აღდგება ხალხი ხალხის წინააღმდეგ და სამეფო სამეფოს წინააღმდეგ, და იქნება მიწისძვრანი ადგილ-ადგილ, იქნება შიმშილობა და შფოთი. და ეს - სალმობათა დასაბამია." },
  { verse: 9, text: "არამედ მიხედეთ თქვენს თავს, რადგანაც მიგცემენ სამართალში, მათრახით გცემენ სინაგოგებში, და მიგიყვანენ ჩემს გამო მთავრებისა და მეფეების წინაშე, რათა უმოწმოთ მათ." },
  { verse: 10, text: "და პირველად ყველა ხალხს უნდა ექადაგოს სახარება." },
  { verse: 11, text: "ხოლო როდესაც წაგიყვანენ გასაცემად, წინასწარ ნუ იზრუნებთ, რა ვთქვათო, და ნურც წინასწარ მოიფიქრებთ სათქმელს; არამედ რაც მოგეცემათ იმ ჟამად, ის ილაპარაკეთ; რადგან თქვენ კი არ ილაპარაკებთ, არამედ - სული წმიდა." },
  { verse: 12, text: "და გასცემს ძმა სასიკვდილოდ ძმას, და მამა - შვილს; შვილები აღდგებიან მშობლების წინააღმდეგ და დახოცავენ მათ." },
  { verse: 13, text: "და მოგიძულებთ ყველა ჩემი სახელის გამო; ხოლო ვინც ბოლომდე დაითმენს, იგი ცხონდება." },
  { verse: 14, text: "როდესაც იხილავთ გაპარტახების სიბილწეს, დანიელ წინასწარმეტყველის მიერ ნათქვამს, რაც უადგილო ადგილას დევს (წამკითხველმა გაიგოს), მაშინ ვინც იუდეაშია, მთებს მიაშუროს." },
  { verse: 15, text: "და ერდოზე მყოფი ნუ ჩამოვა ძირს თავისი სახლიდან რაიმეს გამოსატანად." },
  { verse: 16, text: "მინდვრად მყოფი კი ნუ მიბრუნდება შინ თავისი სამოსის წამოსაღებად." },
  { verse: 17, text: "ვაი ფეხმძიმეთ და მეძუძურთ იმ ხანად." },
  { verse: 18, text: "ილოცეთ, რათა გაქცევამ არ მოგიწიოთ ზამთარში." },
  { verse: 19, text: "რადგან იქნება იმ დღეებში ჭირი, რომლის მსგავსი არ ყოფილა ქვეყნის დასაბამიდან, რომელიც შექმნა ღმერთმა, დღევანდელ დღემდე, და არც იქნება." },
  { verse: 20, text: "და უფალს რომ არ შეემოკლებინა ის დღენი, ვერ გადარჩებოდა ვერც ერთი ძეხორციელი; მაგრამ რჩეულთათვის შეამოკლა ის დღენი." },
  { verse: 21, text: "მაშინ, თუ ვინმე გეტყვით: აჰა, აქ არის ქრისტე, ან კიდევ - იქო, ნუ ერწმუნებით." },
  { verse: 22, text: "რადგან აღდგებიან ცრუქრისტენი და ცრუწინასწარმეტყველნი და მოახდენენ სასწაულებსა და ნიშებს, რათა აცდუნონ, თუკი შესძლეს, თვითონ რჩეულნიც." },
  { verse: 23, text: "ხოლო თქვენ ფხიზლად იყავით. აჰა, ყოველივე წინასწარ გაუწყეთ თქვენ." },
  { verse: 24, text: "და მაშინ, იმ ჭირის შემდეგ, დაბნელდება მზე და მთვარე აღარ გამოსცემს ნათელს." },
  { verse: 25, text: "ვარსკვლავები ჩამოცვივიან ციდან და შეიძვრიან ციურნი ძალნი." },
  { verse: 26, text: "მაშინ იხილავენ ძეს კაცისას, ღრუბლებზე მომავალს დიდებით და მრავალი ძალით." },
  { verse: 27, text: "მაშინ მოავლინებს თავის ანგელოზებს და შეკრებს თავის რჩეულთ ოთხთავ ქართაგან, მიწის კიდიდან ცის კიდემდე." },
  { verse: 28, text: "ლეღვის ხისაგან ისწავლეთ იგავი: როცა მისი ტოტები რბილდება და ფოთლები გამოაქვს, იცით, რომ ახლოა ზაფხული." },
  { verse: 29, text: "ასევე თქვენც, როცა იხილავთ, რთმ ყოველივე ეს ხდება, იცოდეთ, რომ უკვე ახლოა, კარზეა მომდგარი." },
  { verse: 30, text: "ჭეშმარიტად გეუბნებით თქვენ: არ გადავა ეს მოდგმა, ვიდრე ყოველივე ეს არ აღსრულდება." },
  { verse: 31, text: "ცა და მიწა გადავლენ, ხოლო ჩემი სიტყვები არ გადავლენ." },
  { verse: 32, text: "მაგრამ იმ დღისა და იმ საათისა არავინ არაფერი იცის, არც ანგელოზებმა ცაში, არც ძემ, არამედ მხოლოდ მამამ." },
  { verse: 33, text: "ფრთხილად იყავით, იფხიზლეთ და ილოცეთ, რადგან არ იცით, როდის მოაწევს ჟამი." },
  { verse: 34, text: "მსგავსად კაცისა, შორს რომ გაემგზავრა, მიატოვა თავისი სახლი და მისცა თავის მონებს გამგებლობა, თვითეულს თავისი საქმე მიუჩინა და უბრძანა კარის მცველს, ფხიზლად სჭეროდა თვალი." },
  { verse: 35, text: "მაშ, იფხიზლეთ, ვინაიდან არ იცით, როდის მოვა სახლის პატრონი: საღამოს, შუაღამისას, მამლის ყივილისას თუ განთიადისას." },
  { verse: 36, text: "რათა ანაზდად არ მოგისწროთ მძინარეთ." },
  { verse: 37, text: "ხოლო რასაც თქვენ გეუბნებით, ყველას ვეუბნები: იფხიზლეთ." },
],
14: [
  { verse: 1, text: "ორი დღის შემდეგ იყო პასექისა და უფუარობის დღესასწაული. და მღვდელმთავრები და მწიგნობრები ეძებდნენ ხერხს, როგორ შეეპყროთ მზაკვრთბით და მოეკლათ იგი." },
  { verse: 2, text: "მაგრამ ამბობდნენ: ოღონდ არა დღესასწაულზე, რათა ხალხი არ ამბოხდესო." },
  { verse: 3, text: "ხოლო როდესაც ბეთანიაში იყო და ინახად იჯდა სიმონ კეთროვანის სახლში, მოვიდა ქალი, რომელსაც ალებასტრის ჭურჭლით ჰქონდა ნარდის ძვირფასი ნელსაცხებელი, გატეხა ჭურჭელი და თავზე დაასხა მას." },
  { verse: 4, text: "ზოგიერთები აღშფოთდნენ და ერთმანეთს ეუბნებოდნენ: რა საჭიროა ნელსაცხებლის ასეთი ფლანგვა?" },
  { verse: 5, text: "ვინაიდან შეიძლებოდა სამას დინარზე მეტად გაგვეყიდა და გლახაკთათვის მიგვეცა ფული." },
  { verse: 6, text: "ხოლო იესომ თქვა: რას ერჩით, თავი გაანებეთ; მაგან ხომ კეთილი საქმე მიყო." },
  { verse: 7, text: "ვინაიდან გლახაკნი ყოველთვის გვერდითა გყავთ და როცა ინებებთ, მაშინ შეგიძლიათ შეეწიოთ, მე კი ყოველთვის როდი გეყოლებით." },
  { verse: 8, text: "მან გააკეთა ის, რაც შეეძლო: ჩემს სხეულს წინასწარ სცხო ნელსაცხებელი დასამარხავად." },
  { verse: 9, text: "ჭეშმარიტად გეუბნებით თქვენ: მთელს ქვეყანაზე, სადაც იქადაგება ეს სახარება, ყველგან ითქმება მისი საქმე მისსავე მოსაგონებლად." },
  { verse: 10, text: "და იუდა ისკარიოტელი, ერთი თორმეტთაგანი, წავიდა მღვდელმთავრებთან მის გასაცემად." },
  { verse: 11, text: "ხოლო მათ, ეს რომ გაიგეს, გაიხარეს და ვერცხლი აღუთქვეს მას. ის კი ეძებდა ხელსაყრელ დროს, რათა გაეცა იგი." },
  { verse: 12, text: "უფუარობის პირველ დღეს, როცა სწირავდნენ საპასექე კრავს, მოწაფეებმა უთხრეს: სად გნებავს, წავიდეთ და მოგიმზადოთ საჭმელად პასექი?" },
  { verse: 13, text: "გაგზავნა თავისი ორი მოწაფე და უთხრა მათ: წადით ქალაქში და შეგხვდებათ კაცი, რომელსაც დოქით მიაქვს წყალი; მას გაჰყევით." },
  { verse: 14, text: "სადაც შევა, უთხარით იმ სახლის პატრონს: მოძღვარი ამბობს: სად არის დარბაზი, სადაც ჩემს მოწაფეებთან ერთად ვჭამ პასექს?" },
  { verse: 15, text: "ის გიჩვენებთ ვრცელ დარბაზს, გაწყობილს და გამზადებულს, იქ მოგვიმზადეთ." },
  { verse: 16, text: "წავიდნენ მისი მოწაფეები, მივიდნენ ქალაქში და ყველაფერი ისე დახვდათ, როგორც უთხრა იესომ, და მოამზადეს პასექი." },
  { verse: 17, text: "მწუხრის ჟამს მივიდა თორმეტთან ერთად." },
  { verse: 18, text: "როცა ინახად ისხდნენ და ჭამდნენ, იესომ თქვა: ჭეშმარიტად გეუბნებით თქვენ: ერთი თქვენგანი, რომელიც ჩემთან ერთად ჭამს, გამცემს მე." },
  { verse: 19, text: "ხოლო ისინი დამწუხრდნენ და სათითაოდ დაუწყეს კითხვა მას: მე ხომ არაო?" },
  { verse: 20, text: "მიუგო და უთხრა მათ: ერთი თორმეტთაგანი, რომელიც ჩემთან ერთად ჩაყოფს ხელს ჯამში." },
  { verse: 21, text: "და მართლაც, მიდის ძე კაცისა, როგორც დაიწერა მისთვის; მაგრამ ვაი იმ კაცს, ვის მიერაც გაიცემა ძე კაცისა; ერჩია, სულაც არ შობილიყო ის კაცი." },
  { verse: 22, text: "ჭამისას აიღო პური იესომ, აკურთხა, გატეხა, მისცა მათ და უთხრა: აიღეთ, ჭამეთ; ეს არის ჩემი ხორცი." },
  { verse: 23, text: "აიღო სასმისი, აკურთხა და მისცა მათ; და სვამდნენ ყველანი იმით." },
  { verse: 24, text: "უთხრა მათ: ეს არის ჩემი სისხლი ახალი აღთქმისა, მრავალთათვის დათხეული." },
  { verse: 25, text: "ჭეშმარიტად გეუბნებით თქვენ: აღარა ვსვამ ამიერიდან ვაზის ამ ნაყოფისაგან, ვიდრე იმ დღემდე, როცა თქვენთან ერთად შევსვამ ახალს ღმრთის სასუფეველში." },
  { verse: 26, text: "იგალობეს და გავიდნენ ზეთისხილის მთაზე." },
  { verse: 27, text: "უთხრა მათ იესომ: ამაღამ ყველანი შეცდებით ჩემს გამო; ვინაიდან დაწერილია: დავცემ მწყემსს, და განიბნევიან ცხვრები." },
  { verse: 28, text: "ხოლო ჩემი აღდგომის შემდეგ წინ წაგიძღვებით გალილეაში." },
  { verse: 29, text: "პეტრემ უთხრა: შეიძლება ყველანი შეცდნენ, მაგრამ მე - არა." },
  { verse: 30, text: "მიუგო მას იესომ: ჭეშმარიტად გეუბნები: ამაღამ, ვიდრე მამალი მეორედ იყივლებს, სამჯერ უარმყოფ მე." },
  { verse: 31, text: "მაგრამ პეტრე უფრო დაჟინებით ამბობდა: შენთან ერთადაც რომ მიწიოს სიკვდილმა, არ უარგყოფო, და ასევე ამბობდა ყველა." },
  { verse: 32, text: "მივიდნენ იმ ადგილას, რომელსაც ჰქვია გეთსემანე, და თავის მოწაფეებს უთხრა: ისხედით მანდ, ვიდრე ვილოცებ." },
  { verse: 33, text: "წაიყვანა პეტრე, იაკობი და იოანე, და დაიწყო მწუხარება და ურვა." },
  { verse: 34, text: "უთხრა მათ: მწუხარეა ჩემი სული, ვიდრე სიკვდილამდე; იყავით აქ და იფხიზლეთ." },
  { verse: 35, text: "ცოტაზე გაშორდა მათ, მიწაზე დაემხო და ლოცულობდა, რათა, თუკი შესაძლო იყო, ასცდენოდა ეს საათი;" },
  { verse: 36, text: "ამბობდა: აბბა, მამაო! ყველაფერი შესაძლებელია შენთვის; ამარიდე ეს სასმისი; თუმცა არა რაც მე მნებავს, არამედ რაც შენ." },
  { verse: 37, text: "დაბრუნებულმა მძინარენი ნახა ისინი და უთხრა პეტრეს: სიმონ, გძინავს? ერთ საათსაც ვერ გასძელი ფხიზლად ყოფნა?" },
  { verse: 38, text: "იფხიზლეთ და ილოცეთ, რათა არ შეხვიდეთ საცდუნებელში; სული მხნეა, მაგრამ ხორცია უძლური." },
  { verse: 39, text: "კვლავ გაშორდა მათ და იმავე სიტყვებით ილოცა." },
  { verse: 40, text: "როცა დაბრუნდა, კვლავინდებურად მძინარენი ნახა ისინი, ვინაიდან თვალები დამძიმებოდათ, და არ იცოდნენ, რა მიეგოთ მისთვის." },
  { verse: 41, text: "მესამედაც მოვიდა, და უთხრა მათ: ისევ გძინავთ და განისვენებთ? კმარა, მოაწია დრომ: აჰა, მიეცემა ძე კაცისა ცოდვილთა ხელში." },
  { verse: 42, text: "ადექით, წავიდეთ; აჰა მოგვიახლოვდა ჩემი გამცემი." },
  { verse: 43, text: "სიტყვა არ დაესრულებინა, რომ მოვიდა იუდა, ერთი თორმეტთაგანი, და მასთან ერთად დიდძალი ხალხი მახვილებითა და წათებით მღვდელმთავართა, მწიგნობართა და უხუცესთაგან." },
  { verse: 44, text: "ხოლო მის გამცემს ნიშანი მიეცა მათთვის და ეთქვა: ვისაც მე ვეამბორები, ის არის; შეიპყარით და ფრთხილად წაიყვანეთ." },
  { verse: 45, text: "მოსვლისთანავე მიეახლა და უთხრა: რაბი, რაბი! და ეამბორა მას." },
  { verse: 46, text: "ხოლო მათ ხელი სტაცეს და შეიპყრეს იგი." },
  { verse: 47, text: "ერთმა იქ მდგომთაგანმა ხმალი იშიშვლა, დაჰკრა მღვდელმთავრის მონას და ყური ჩამოათალა." },
  { verse: 48, text: "მიუგო იესომ და უთხრა მათ: როგორც ავაზაკს, მახვილებითა და წათებით მომიხტით შესაპყრობად." },
  { verse: 49, text: "დღენიადაგ თქვენთან ვიჯექი და გასწავლიდით ტაძარში, და არ შეგიპყრივართ. მაგრამ აღსრულდეს წერილი." },
  { verse: 50, text: "მაშინ ყველამ მიატოვა ის და გაიქცა." },
  { verse: 51, text: "ერთი ჭაბუკი, რომელსაც შიშველ ტანზე ტილო შემოეხვია, მისდევდა მას, და მეომრებმა შეიპყრეს იგი." },
  { verse: 52, text: "ხოლო მან ტილო შეატოვა ხელში და შიშველი გაექცა მათ." },
  { verse: 53, text: "მიიყვანეს იესო მღვდელმთავართან; და შეგროვდა მასთან ყველა მღვდელმთავარი, მწიგნობარი და უხუცესი." },
  { verse: 54, text: "ხოლო პეტრე შორით მისდევდა, ვიდრე არ შევიდა მღვდელმთავრის ეზოში; მსახურებთან ერთად მიუჯდა ცეცხლს და თბებოდა." },
  { verse: 55, text: "მღვდელმთავარნი და მთელი სინედრიონი მოწმეებს ეძებდნენ იესოს წინააღმდეგ, რათა მოეკლათ იგი, მაგრამ ვერ პოულობდნენ." },
  { verse: 56, text: "რადგან ბევრი იყო ცრუმოწმე, მაგრამ მათი მოწმობანი არ ემთხვეოდნენ ერთმანეთს." },
  { verse: 57, text: "ზოგიერთი ადგა, ცრუმოწმობდა მის წინააღმდეგ და ამბობდა:" },
  { verse: 58, text: "ჩვენ გვსმენია მაგის ნათქვამი: დავანგრევ ამ ხელთქმნილ ტაძარს და სამ დღეში ახალს ავაგებ, ხელთუქმნელსო." },
  { verse: 59, text: "მაგრამ არც ეს მათი მოწმობანი ემთხვეოდა ერთმანეთს." },
  { verse: 60, text: "მაშინ შუაში ჩადგა მღვდელმთავარი და ჰკითხა იესოს: რატომ არაფერს იტყვი პასუხად, ესენი რომ მოწმობენ შენს წინააღმდეგ?" },
  { verse: 61, text: "ხოლო ის დუმდა და არაფერი მიუგო მათ. მაშინ კვლავ ჰკითხა მღვდელმთავარმა: შენ ხარ ქრისტე, ძე კურთხეულისა?" },
  { verse: 62, text: "იესომ მიუგო: მე ვარ. იხილავთ ძეს კაცისას, მჯდომარეს ძალის მარჯვნივ და მომავალს ზეცის ღრუბლებით." },
  { verse: 63, text: "მაშინ მღვდელმთავარმა შემოიხია სამოსი და თქვა: რაღად გვინდა მოწმენი?" },
  { verse: 64, text: "ხომ მოისმინეთ ღვთის გმობა? რას იტყვით? მაშინ ყველამ სიკვდილის ღირსად სცნო იგი." },
  { verse: 65, text: "ზოგიერთებმა დაუწყეს ფურთხება, სახეს უფარავდნენ, ურტყამდნენ და ეუბნებოდნენ: გვიწინასწარმეტყველე. მსახურები კი ყვრიმალში სცემდნენ მას." },
  { verse: 66, text: "ხოლო, როცა პეტრე ქვემოთ, ეზოში იყო, მოვიდა მღვდელმთავრის ერთი მხევალი" },
  { verse: 67, text: "და, ცეცხლს მიფიცხებული პეტრე რომ დაინახა, დააკვირდა და უთხრა მას: შენც ხომ იესო ნაზარეველთან იყავი?" },
  { verse: 68, text: "მაგრამ მან უარყო და თქვა: არ ვიცი, არ მესმის, რას ამბობ; ეზოდან გავიდა, და იყივლა კიდეც მამალმა." },
  { verse: 69, text: "მხევალმა კვლავ შეასწრო თვალი და იქვე მდგომთ უთხრა: ესეც ერთი მათგანიაო." },
  { verse: 70, text: "მან კვლავ უარყო. ცოტა ხნის შემდეგ იქვე მდგომებმაც უთხრეს პეტრეს: მართლაც ერთი მათგანი ხარ, რადგან კილოზე გეტყობა, რომ გალილეველი უნდა იყო." },
  { verse: 71, text: "ხოლო ის მოჰყვა წყევლას და ფიცს: არ ვიცნობ იმ კაცს, ვისზედაც მელაპარაკებითო; და მეორედ იყივლა მამალმა." },
  { verse: 72, text: "გაახსენდა პეტრეს იესოს ნათქვამი: მამლის მეორე ყივილამდე სამჯერ უარმყოფო, და ტირილი დაიწყო." },
],
  15: [
  { verse: 1, text: "ინათა თუ არა, ბჭობა გამართეს მღვდელმთავრებმა უხუცესებთან, მწიგნობრებსა და მთელ სინედრიონთან ერთად. შეკრეს იესო, წაიყვანეს და მისცეს პილატეს." },
  { verse: 2, text: "პილატემ ჰკითხა მას: შენა ხარ იუდეველთა მეფე? ხოლო იესომ მიუგო და უთხრა: შენ ამბობ." },
  { verse: 3, text: "მღვდელმთავრები ბევრ რასმე სდებდნენ ბრალად." },
  { verse: 4, text: "ხოლო პილატემ კვლავ ჰკითხა მას: რატომ არაფერს იტყვი პასუხად? ხედავ, რამდენ რასმე გწამებენ?" },
  { verse: 5, text: "მაგრამ იესომ ამჯერადაც არა მიუგო რა, ასე რომ, უკვირდა პილატეს." },
  { verse: 6, text: "ხოლო ყოველ დღესასწაულზე ათავისუფლებდა იგი ერთ პატიმარს, რომელსაც სთხოვდა ხალხი." },
  { verse: 7, text: "და იყო მაშინ ვინმე ბარაბა, ბორკილდადებული მეამბოხეებთან ერთად, რომლებსაც მკვლელობა ჩაედინათ ამბოხებისას." },
  { verse: 8, text: "მოვიდა ხალხი და დაუწყო იმისი თხოვნა, რასაც პილატე ყოველთვის უსრულებდა მათ." },
  { verse: 9, text: "ხოლო პილატემ მიუგო და უთხრა მათ: თუ გნებავთ გაგითავისუფლებთ იუდეველთა მეფეს." },
  { verse: 10, text: "რადგან იცოდა, რომ მღვდელმთავრებმა შურით გასცეს იგი." },
  { verse: 11, text: "მაგრამ მღვდელმთავრებმა წააქეზეს ხალხი, რათა უმალ ბარაბა გაეთავისუფლებინა მათთვის." },
  { verse: 12, text: "ხოლო პილატემ მიუგო და კვლავ უთხრა მათ: კი მაგრამ, რა გსურთ, რა ვუყო იმას, ვისაც იუდეველთა მეფეს უწოდებთ?" },
  { verse: 13, text: "ისინი კვლავ აყვირდნენ: ჯვარს აცვი იგი!" },
  { verse: 14, text: "პილატემ თქვა: რა დააშავა? მაგრამ ისინი უფრო ხმამაღლა აყვირდნენ: ჯვარს აცვი იგი!" },
  { verse: 15, text: "მაშინ პილატემ, ხალხის მოსამადლიერებლად, გაათავისუფლა ბარაბა, ხოლო იესო გაამათრახებინა და ჯვარზე საცმელად მისცა მათ." },
  { verse: 16, text: "ჯარისკაცებმა შიდა ეზოში, ანუ პრეტორიუმში შეიყვანეს იგი, და შეკრიბეს მთელი რაზმი." },
  { verse: 17, text: "შემოსეს ძოწეულით, დაწნეს ეკლის გვირგვინი და თავზე დაადგეს." },
  { verse: 18, text: "და დაუწყეს მისალმება: გიხაროდეს, იუდეველთა მეფევ!" },
  { verse: 19, text: "თავზე ამტვრევდნენ ლერწამს, აფურთხებდნენ და მუხლმოყრილნი თაყვანსა სცემდნენ." },
  { verse: 20, text: "ხოლო როცა დაცინვით გული იჯერეს, შემოაძარცვეს ძოწეული, კვლავ თავისი სამოსი ჩააცვეს და ჯვარზე საცმელად წაიყვანეს იგი." },
  { verse: 21, text: "და აიძულეს მინდვრიდან მომავალი ერთი კირენელი კაცი, სახელად სიმონი, ალექსანდრესა და რუფუსის მამა, ეტვირთა იესოს ჯვარი." },
  { verse: 22, text: "მიიყვანეს იგი იმ ადგილას, რომელსაც ჰქვია გოლგოთა, რაც ნიშნავს თხემის ადგილს." },
  { verse: 23, text: "და მისცეს მას სასმელად მურნარევი ღვინო, მაგრამ არ მიიღო." },
  { verse: 24, text: "ჯვარს აცვეს იგი და წილისყრით გაიყვეს მისი სამოსი: ვის რა შეგვხვდებაო." },
  { verse: 25, text: "ხოლო იყო მესამე საათი, როცა ჯვარს აცვეს იგი." },
  { verse: 26, text: "და მისი ბრალი ამ წარწერით იყო გადმოცემული: იუდეველთა მეფე." },
  { verse: 27, text: "მასთან ერთად ჯვარს აცვეს ორი ავაზაკი, ერთი მის მარჯვნივ და მეორე - მარცხნივ." },
  { verse: 28, text: "და აღსრულდა წერილი, რომელიც ამბობს: ბოროტმოქმედთა შორის შეირაცხაო." },
  { verse: 29, text: "ხოლო გამვლელნი აგინებდნენ, თავებს აქნევდნენ და ამბობდნენ: ეჰა, ტაძრის დამრღვევო და სამ დღეში აღმშენებელო!" },
  { verse: 30, text: "იხსენი შენი თავი; ჩამოდი ჯვრიდან!" },
  { verse: 31, text: "ასევე მღვდეღმთავრები, მწიგნობრებთან ერთად, დასცინოდნენ და ერთმანეთს ეუბნებოდნენ: სხვები იხსნა და თავის ხსნა კი არ შეუძლია;" },
  { verse: 32, text: "ქრისტე, მეფე ისრაელისა, დე, ჩამოვიდეს ახლა ჯვრიდან, რათა ვიხილოთ და ვიწამოთ. და მასთან ერთად ჯვარცმულნი აგინებდნენ მას." },
  { verse: 33, text: "ხოლო მეექვსე საათის დამდეგს მეცხრე საათამდე წყვდიადმა მოიცვა მთელი ქვეყანა." },
  { verse: 34, text: "მეცხრე საათს ხმამაღლა შეღაღადა იესომ: ელოი, ელოი, ლამა საბაქთანი? რაც თარგმანით ნიშნავს: ღმერთო ჩემო, ღმერთო ჩემო, რატომ მიმატოვე მე?" },
  { verse: 35, text: "ზოგიერთმა იქ მდგომმა გაიგონა ეს და თქვა: აჰა, ელიას უხმობსო." },
  { verse: 36, text: "ერთი კი გაიქცა, ძმრით გაჟღენთა ღრუბელი, ლერწამზე წამოაგო, სასმელად მისცა და ამბობდა: მოიცათ, ვნახოთ, მოვა თუ არა ელია მის ჩამოსახსნელად." },
  { verse: 37, text: "ხოლო იესომ კვლავ შეღაღადა ხმამაღლა და განუტევა სული." },
  { verse: 38, text: "მაშინ, ზემოდან ქვემომდე, შუა ჩაიხა ტაძრის ფარდა." },
  { verse: 39, text: "როცა მის პირდაპირ მდგარმა ასისთავმა დაინახა, რომ ასე შეღაღადა და განუტევა სული, თქვა: ჭეშმარიტად ეს კაცი ძე იყო ღმრთისა." },
  { verse: 40, text: "იყვნენ იქ შორიდან მაცქერალი ქალებიც, მათ შორის, მარიამ მაგდალელი, მარიამი, იაკობ მცირისა და იოსეს დედა, და სალომე," },
  { verse: 41, text: "რომლებიც თან დაჰყვებოდნენ, როცა გალილეაში იყო, და ემსახურებოდნენ მას; და სხვაც მრავალი, მასთან ერთად ამოსული იერუსალიმს." },
  { verse: 42, text: "მწუხრის ჟამს - ვინაიდან პარასკევი იყო, შაბათის წინა დღე, -" },
  { verse: 43, text: "მოვიდა იოსებ არიმათიელი, მრჩეველთა კეთილშობილი წევრი, თვითონაც რომ მოელოდა ღმრთის სასუფეველს, თამამად შევიდა პილატესთან და გამოითხოვა იესოს გვამი." },
  { verse: 44, text: "ხოლო პილატეს გაუკვირდა, განა უკვე მოკვდაო? მოუხმო ასისთავს და ჰკითხა: დიდიხანია მოკვდა?" },
  { verse: 45, text: "და როცა შეიტყო ასისთავისგან, მისცა იოსებს მისი გვამი." },
  { verse: 46, text: "ხოლო მან იყიდა ტილო და ჩამოხსნა იგი ჯვრიდან, გახვია ტილოში და სამარხში დაასვენა, რომელიც კლდეში იყო გამოკვეთილი, და ლოდი მიაყუდა სამარხის კარს." },
  { verse: 47, text: "ხოლო მარიამ მაგდალელი და მარიამ იოსესი ხედავდნენ, სადაც დაასვენეს იგი." },
],
16: [
  { verse: 1, text: "და როცა გავიდა შაბათი, მარიამ მაგდალელმა, მარიამ იაკობისამ და სალომემ იყიდეს ნელსაცხებელი, რათა მისულიყვნენ და ეცხოთ მისთვის." },
  { verse: 2, text: "კვირის პირველ დღეს, დილაადრიან, მზის ამოსვლისას მივიდნენ სამარხთან." },
  { verse: 3, text: "და ერთმანეთს ეუბნებოდნენ: ვინ გადმოგვიგორებს ლოდს სამარხის კარიდანო?" },
  { verse: 4, text: "მაგრამ დაინახეს, რომ ლოდი გადაგორებულია, ხოლო ის ძალიან დიდი იყო." },
  { verse: 5, text: "შევიდნენ სამარხში და იხილეს მარჯვნივ მჯდომარე ჭაბუკი, თეთრი სამოსით მოსილი, და შეკრთნენ." },
  { verse: 6, text: "ხოლო მან უთხრა: ნუ შეკრთებით! თქვენ ეძებთ ჯვარცმულ იესო ნაზარეველს; აღსდგა, აქ აღარ არის; აი, ამ ადგილას ესვენა იგი." },
  { verse: 7, text: "მაშ, წადით, უთხარით მის მოწაფეებს და პეტრეს: წინ წაგიძღვებათ გალილეისკენ, და იქ იხილავთ, როგორც გაუწყათ თქვენ." },
  { verse: 8, text: "გამოვიდნენ და სირბილით გაშორდნენ საფლავს; ცახცახს და ძრწოლას მოეცვა ისინი, და არავისთვის არა უთქვამთ რა, რადგან ეშინოდათ." },
  { verse: 9, text: "ხოლო კვირის პირველ დღეს დილაადრიანად აღმდგარი იესო პირველად ეჩვენა მარიამ მაგდალელს, რომლისგანაც გაეძევებინა შვიდი ეშმაკი." },
  { verse: 10, text: "ისიც წავიდა და აუწყა მასთან მყოფთ, რომელნიც ტიროდნენ და მოთქვამდნენ." },
  { verse: 11, text: "მათ კი, თუმცა გაიგეს, რომ ცოცხალია და მან იხილა იგი, არ ირწმუნეს." },
  { verse: 12, text: "ამის შემდეგ სხვა სახით ეჩვენა ორ მათგანს, სოფელში რომ მიდიოდნენ." },
  { verse: 13, text: "ხოლო ისინი დაბრუნდნენ და აუწყეს დანარჩენთ; მაგრამ არც მათ ერწმუნენ." },
  { verse: 14, text: "დაბოლოს, ეჩვენა თვით ინახად მსხდომ თერთმეტს, და დაჰგმო მათი ურწმუნოება და გულქვაობა, რადგან არ ერწმუნენ არავის, ვინც აღმდგარი იხილა იგი." },
  { verse: 15, text: "და უთხრა მათ: წადით, მოიარეთ მთელი ქვეყანა და უქადაგეთ სახარება ყველა ქმნილებას." },
  { verse: 16, text: "ვინც იწამებს და ნათელს იღებს, ცხონდება, ვინც არა და, განიკითხება." },
  { verse: 17, text: "ხოლო მორწმუნეთაგან განუყრელნი იქნებიან ეს სასწაულნი: ჩემი სახელით განდევნიან ეშმაკთ და ახალ ენებზე იმეტყველებენ." },
  { verse: 18, text: "აიყვანენ გველებს, და თუ სასიკვდილოს დალევენ რასმე, არ ავნებს მათ; ხელს დაადებენ სნეულთ და განიკურნებიან ისინი." },
  { verse: 19, text: "ასე, მათთან საუბრის შემდეგ, ამაღლდა უფალი ზეცად, და დაჯდა ღმრთის მარჯვნივ." },
  { verse: 20, text: "ხოლო ისინი წავიდნენ და ქადაგებდნენ ყველგან უფლის შეწევნით, რომელიც განამტკიცებდა სიტყვას მათი თანმხლები სასწაულებით, ამინ." },
],
};